	public async void LoadApp()
	{
		InitializeComponent();
		((UIElement)SetupScreenGrid).Visibility = (Visibility)0;
		((UIElement)SetupScreen_InitialLoadButton).Visibility = (Visibility)1;
		HideOverlay();
		Main main = this;
		Rect workArea = SystemParameters.WorkArea;
		((FrameworkElement)main).Height = ((Rect)(ref workArea)).Height / 1.5;
		Main main2 = this;
		workArea = SystemParameters.WorkArea;
		((FrameworkElement)main2).Width = ((Rect)(ref workArea)).Width / 1.5;
		ThemeManager.Current.ApplicationTheme = ApplicationTheme.Dark;
		await Task.Delay(2000);
		Progress<int> progress = new Progress<int>(delegate(int value)
		{
			((RangeBase)progressBar).Value = value;
		});
		await Task.Run(delegate
		{
			for (int i = 0; i < 100; i++)
			{
				((IProgress<int>)progress).Report(i);
				Thread.Sleep(10);
			}
		});
		if (!(((RangeBase)progressBar).Value > 95.0))
		{
			return;
		}
		((UIElement)progressBar).Visibility = (Visibility)1;
		if (!GlobalVar.Savefile.SaveFile_IsSetupComplete)
		{
			((UIElement)SetupScreenGrid).Visibility = (Visibility)0;
			((UIElement)SetupScreen_InitialLoadButton).Visibility = (Visibility)0;
			LoadSetupScreen();
		}
		else
		{
			try
			{
				string[] files = Directory.GetFiles("C:\\Temp\\DualSenseX\\Localization");
				CultureInfo.GetCultures(CultureTypes.AllCultures);
				for (int num = 0; num < files.Length; num++)
				{
					string name = new FileInfo(files[num]).Name;
					if (!name.Contains("LanguageList"))
					{
						LocalizationManager.Instance.AddCulture(CultureInfo.GetCultureInfo(Path.GetFileNameWithoutExtension(name)), new JsonFileReader("C:\\Temp\\DualSenseX\\Localization\\" + Path.GetFileNameWithoutExtension(name) + ".json"));
						LanguageListTempFolder.Add("C:\\Temp\\DualSenseX\\Localization\\" + Path.GetFileNameWithoutExtension(name) + ".json");
					}
				}
				foreach (CultureInfo availableCulture in LocalizationManager.Instance.AvailableCultures)
				{
					if (availableCulture.EnglishName == GlobalVar.Savefile.SaveFile_Language)
					{
						LocalizationManager.Instance.CurrentCulture = availableCulture;
						RefreshTranslationLabelsTimer = new DispatcherTimer();
						RefreshTranslationLabelsTimer.Interval = new TimeSpan(0, 0, 0, 0, 20);
						RefreshTranslationLabelsTimer.Tick += RefreshTranslationLabelsTimerFunc;
						RefreshTranslationLabelsTimer.Start();
					}
				}
			}
			catch (Exception)
			{
			}
			if (!new InternetConnectionChecker().IsConnectedToInternet())
			{
				try
				{
					string[] files2 = Directory.GetFiles("C:\\Temp\\DualSenseX\\Localization");
					CultureInfo.GetCultures(CultureTypes.AllCultures);
					for (int num2 = 0; num2 < files2.Length; num2++)
					{
						string name2 = new FileInfo(files2[num2]).Name;
						if (!name2.Contains("LanguageList"))
						{
							LocalizationManager.Instance.AddCulture(CultureInfo.GetCultureInfo(Path.GetFileNameWithoutExtension(name2)), new JsonFileReader("C:\\Temp\\DualSenseX\\Localization\\" + Path.GetFileNameWithoutExtension(name2) + ".json"));
							LanguageListTempFolder.Add("C:\\Temp\\DualSenseX\\Localization\\" + Path.GetFileNameWithoutExtension(name2) + ".json");
							Uri uri = new Uri("/Assets/en-US-Flag.png", UriKind.Relative);
							LanguageListComboBox languageListComboBox = new LanguageListComboBox();
							languageListComboBox.LanguageName = CultureInfo.GetCultureInfo(Path.GetFileNameWithoutExtension(name2)).EnglishName;
							if (CultureInfo.GetCultureInfo(Path.GetFileNameWithoutExtension(name2)).Name == "en-US")
							{
								languageListComboBox.LanguageImage = uri.ToString();
							}
							LangagueListCombo.Add(languageListComboBox);
						}
					}
					foreach (CultureInfo availableCulture2 in LocalizationManager.Instance.AvailableCultures)
					{
						if (availableCulture2.EnglishName == GlobalVar.Savefile.SaveFile_Language)
						{
							LocalizationManager.Instance.CurrentCulture = availableCulture2;
							RefreshTranslationLabelsTimer = new DispatcherTimer();
							RefreshTranslationLabelsTimer.Interval = new TimeSpan(0, 0, 0, 0, 20);
							RefreshTranslationLabelsTimer.Tick += RefreshTranslationLabelsTimerFunc;
							RefreshTranslationLabelsTimer.Start();
						}
					}
					((ItemsControl)SettingsPage_LangaugesList).ItemsSource = LangagueListCombo;
					foreach (LanguageListComboBox item in LangagueListCombo)
					{
						if (item.LanguageName.Contains("United States"))
						{
							((Selector)SettingsPage_LangaugesList).SelectedItem = item;
							((UIElement)SettingsPage_LangaugesList).IsEnabled = true;
						}
					}
				}
				catch (Exception)
				{
				}
			}
			if (SettingsPage_App_DarkModeToggle.IsOn)
			{
				ThemeManager.Current.ApplicationTheme = ApplicationTheme.Dark;
				((Shape)App_Rec1).Fill = (Brush)(object)Brushes.Black;
				((Shape)App_Rec2).Fill = (Brush)(object)Brushes.Black;
				Brush background = (Brush)((TypeConverter)new BrushConverter()).ConvertFromString("#4CFFFFFF");
				App_Rec3.Background = background;
				((Shape)App_Rec4).Fill = (Brush)(object)Brushes.White;
			}
			else
			{
				ThemeManager.Current.ApplicationTheme = ApplicationTheme.Light;
				((Shape)App_Rec1).Fill = (Brush)(object)Brushes.White;
				((Shape)App_Rec2).Fill = (Brush)(object)Brushes.White;
				Brush background2 = (Brush)((TypeConverter)new BrushConverter()).ConvertFromString("#4C000000");
				App_Rec3.Background = background2;
				((Shape)App_Rec4).Fill = (Brush)(object)Brushes.Black;
			}
			((UIElement)SetupScreenGrid).Visibility = (Visibility)1;
			DownloadLanguageListFromDrive(IsSetup: false);
			OnApplicationLaunch();
		}
		GlobalVar.IsAppLaunched = true;
		AppNotificationImage.Source = null;
		((ContentControl)AppNotificationLabel).Content = "";
		((UIElement)AppNotificationButton1).Visibility = (Visibility)1;
		((UIElement)AppNotificationButton2).Visibility = (Visibility)1;
		((UIElement)GamesPageGrid).Visibility = (Visibility)1;
		((UIElement)InputPageGrid).Visibility = (Visibility)1;
		((UIElement)Sense2KeyPageGrid).Visibility = (Visibility)1;
		((UIElement)SettingsPageGrid).Visibility = (Visibility)1;
		((UIElement)InfoPageGrid).Visibility = (Visibility)1;
		((UIElement)HomePageGrid).Visibility = (Visibility)0;
		((UIElement)MenuHomeRectangle).Opacity = 1.0;
		((UIElement)MenuGamesRectangle).Opacity = 0.0;
		((UIElement)MenuInputRectangle).Opacity = 0.0;
		((UIElement)MenuSense2KeyRectangle).Opacity = 0.0;
		((UIElement)MenuSettingsRectangle).Opacity = 0.0;
		((UIElement)MenuHelpRectangle).Opacity = 0.0;
		DisableUIElements();
		((UIElement)SettingsPage_EnableHidHideToggle).IsEnabled = false;
	}

	private void RefreshTranslationLabelsTimerFunc(object sender, EventArgs e)
	{
		RefreshTranslationLabels();
	}

	private void RefreshTranslationLabels()
	{
		try
		{
			((ContentControl)HomePage_NotepadStatusLabel).Content = LocalizationManager.Instance.GetValue(GLDT.HomePage_NotepadStatusLabel_Content);
			((ContentControl)HomePage_CommandNotepadStatusLabel).Content = LocalizationManager.Instance.GetValue(GLDT.HomePage_CommandNotepadStatusLabel_Content);
			HomePage_GameNameLabelTextAccess.Text = LocalizationManager.Instance.GetValue(GLDT.HomePage_GameNameLabelTextAccess_Text) + " " + GameNameCommand;
			((ContentControl)HomePage_ConnectionStatus_ConnectionLabel).Content = LocalizationManager.Instance.GetValue(GLDT.HomePage_ConnectionStatus_ConnectionLabel_Content);
			if (GlobalVar.IsControllerConnectedStatus)
			{
				((ContentControl)HomePage_ConnectionStatus_EmulationTypeLabel).Content = LocalizationManager.Instance.GetValue(GLDT.HomePage_ConnectionStatus_EmulationTypeLabel_Content);
				((ContentControl)HomePage_ConnectionStatus_ConnectionTypeLabel).Content = LocalizationManager.Instance.GetValue("ControllerPage_ConnectionTypeLabel") + " " + connectedController.GetConnectionType();
			}
			else
			{
				((ContentControl)HomePage_ConnectionStatus_EmulationTypeLabel).Content = "";
				((ContentControl)HomePage_ConnectionStatus_ConnectionTypeLabel).Content = "";
			}
			if (((UIElement)Sense2KeyPageGrid).IsVisible)
			{
				((ContentControl)Sense2Key_Selected_ProfileStatusLabel).Content = LocalizationManager.Instance.GetValue(GLDT.Sense2Key_Selected_ProfileStatusLabel_Content);
			}
		}
		catch (Exception)
		{
		}
	}

	private async void OnApplicationLaunch()
	{
		GLDT.HomePage_NotepadStatusLabel_Content = "HomePage_TextFile_StatusNotActiveLabel";
		GLDT.HomePage_CommandNotepadStatusLabel_Content = "HomePage_TextFile_StatusNotActiveLabel";
