	private static string GetDeviceModelId(string devicePath)
	{
		try
		{
			string text = devicePath.Replace("#", "\\");
			text = text.Replace("\\\\?\\hid", "hid");
			if (text.Count((char x) => x == '\\') > 2)
			{
				text = text.Substring(0, text.LastIndexOf("\\"));
			}
			return text;
		}
		catch (Exception)
		{
			return string.Empty;
		}
	}

