				iniFile.Write(SaveFileEnum.SaveFile_EnableTouchpadToMouse.ToString(), GlobalVar.Savefile.SaveFile_EnableTouchpadToMouse.ToString());
				iniFile.Write(SaveFileEnum.SaveFile_InvertScrolling.ToString(), GlobalVar.Savefile.SaveFile_InvertScrolling.ToString());
				iniFile.Write(SaveFileEnum.SaveFile_TouchpadToMouse_ScrollSpeed.ToString(), GlobalVar.Savefile.SaveFile_TouchpadToMouse_ScrollSpeed.ToString());
				iniFile.Write(SaveFileEnum.SaveFile_TouchpadToMouse_SlowSensi.ToString(), GlobalVar.Savefile.SaveFile_TouchpadToMouse_SlowSensi.ToString());
				iniFile.Write(SaveFileEnum.SaveFile_TouchpadToMouse_FastSensi.ToString(), GlobalVar.Savefile.SaveFile_TouchpadToMouse_FastSensi.ToString());
				iniFile.Write(SaveFileEnum.SaveFile_TouchpadToMouse_NormalSensi.ToString(), GlobalVar.Savefile.SaveFile_TouchpadToMouse_NormalSensi.ToString());
				iniFile.Write(SaveFileEnum.SaveFile_TouchpadToMouse_SlowSensiButton.ToString(), GlobalVar.Savefile.SaveFile_TouchpadToMouse_SlowSensiButton.ToString());
				iniFile.Write(SaveFileEnum.SaveFile_TouchpadToMouse_FastSensiButton.ToString(), GlobalVar.Savefile.SaveFile_TouchpadToMouse_FastSensiButton.ToString());
				iniFile.Write(SaveFileEnum.SaveFile_TouchpadToMouse_LeftClickPressedButton.ToString(), GlobalVar.Savefile.SaveFile_TouchpadToMouse_LeftClickPressedButton.ToString());
				iniFile.Write(SaveFileEnum.SaveFile_TouchpadToMouse_RightClickButton.ToString(), GlobalVar.Savefile.SaveFile_TouchpadToMouse_RightClickButton.ToString());
				iniFile.Write(SaveFileEnum.SaveFile_AudioHaptics_Delay.ToString(), GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_AudioHaptics_Delay.ToString());
			}
			else if (iniFile.Read(SaveFileEnum.SaveFile_EnableTouchpadToMouse.ToString()) == "True")
			{
				GlobalVar.Savefile.SaveFile_EnableTouchpadToMouse = true;
			}
			else
			{
				GlobalVar.Savefile.SaveFile_EnableTouchpadToMouse = false;
			}
			if (iniFile.Read(SaveFileEnum.SaveFile_InvertScrolling.ToString()) == "True")
			{
				GlobalVar.Savefile.SaveFile_InvertScrolling = true;
			}
			else
			{
				GlobalVar.Savefile.SaveFile_InvertScrolling = false;
			}
			GlobalVar.Savefile.SaveFile_TouchpadToMouse_ScrollSpeed = int.Parse(iniFile.Read(SaveFileEnum.SaveFile_TouchpadToMouse_ScrollSpeed.ToString()));
			GlobalVar.Savefile.SaveFile_TouchpadToMouse_SlowSensi = int.Parse(iniFile.Read(SaveFileEnum.SaveFile_TouchpadToMouse_SlowSensi.ToString()));
			GlobalVar.Savefile.SaveFile_TouchpadToMouse_FastSensi = int.Parse(iniFile.Read(SaveFileEnum.SaveFile_TouchpadToMouse_FastSensi.ToString()));
			GlobalVar.Savefile.SaveFile_TouchpadToMouse_NormalSensi = int.Parse(iniFile.Read(SaveFileEnum.SaveFile_TouchpadToMouse_NormalSensi.ToString()));
			GlobalVar.Savefile.SaveFile_TouchpadToMouse_SlowSensiButton = (DSButtonsEnum)Enum.Parse(typeof(DSButtonsEnum), iniFile.Read(SaveFileEnum.SaveFile_TouchpadToMouse_SlowSensiButton.ToString()));
			GlobalVar.Savefile.SaveFile_TouchpadToMouse_FastSensiButton = (DSButtonsEnum)Enum.Parse(typeof(DSButtonsEnum), iniFile.Read(SaveFileEnum.SaveFile_TouchpadToMouse_FastSensiButton.ToString()));
			GlobalVar.Savefile.SaveFile_TouchpadToMouse_LeftClickPressedButton = (DSButtonsEnum)Enum.Parse(typeof(DSButtonsEnum), iniFile.Read(SaveFileEnum.SaveFile_TouchpadToMouse_LeftClickPressedButton.ToString()));
			GlobalVar.Savefile.SaveFile_TouchpadToMouse_RightClickButton = (DSButtonsEnum)Enum.Parse(typeof(DSButtonsEnum), iniFile.Read(SaveFileEnum.SaveFile_TouchpadToMouse_RightClickButton.ToString()));
			GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_AudioHaptics_Delay = int.Parse(iniFile.Read(SaveFileEnum.SaveFile_AudioHaptics_Delay.ToString()));
		}
		catch (Exception ex)
		{
			Exception exp = ex;
			((DispatcherObject)this).Dispatcher.Invoke<Task>((Func<Task>)async delegate
			{
				if ((int)CustomMessageBox.ShowOKCancel("Oops an error occured!\n\n\n" + exp.Message, "DualSenseX", "Reset and Restart App", "Close App", (MessageBoxImage)48) == 1)
				{
					if (Directory.Exists("C:\\Temp\\DualSenseX"))
					{
						if (App_TaskBarIcon != null)
						{
							((UIElement)App_TaskBarIcon).Visibility = (Visibility)1;
						}
						File.Delete("C:\\Temp\\DualSenseX\\DualSenseX_SaveFile_INI.ini");
						if (App_TaskBarIcon != null)
						{
							((UIElement)App_TaskBarIcon).Visibility = (Visibility)1;
						}
						await Task.Delay(2000);
						Application.Restart();
						Environment.Exit(0);
					}
				}
				else
				{
					if (App_TaskBarIcon != null)
					{
						((UIElement)App_TaskBarIcon).Visibility = (Visibility)1;
					}
					await Task.Delay(2000);
					Application.Current.Shutdown();
					Environment.Exit(0);
				}
			});
		}
	}

