	private async void StystemTrayExitBtn(object sender, RoutedEventArgs e)
	{
		((UIElement)this).Focus();
		if (connectedController.IsControllerConnected())
		{
			if ((int)((Window)this).WindowState == 1)
			{
				((Window)this).Show();
				((Window)this).WindowState = (WindowState)0;
			}
			if (GlobalVar.IsControllerConnectedStatus)
			{
				UpdateAvailabelDialog.Hide();
				DownloadLatesDialog.Hide();
				if (!((FrameworkElement)ExitDialog).IsLoaded)
				{
					ExitDialog.Title = LocalizationManager.Instance.GetValue("AppNotificationPopUp_AreYouSureYouWantToExit");
					if (GlobalVar.Savefile.SaveFile_ControllerEmulation == EmulationType.OFF)
					{
						ExitDialog.BodyText.Text = "";
					}
					else if (GlobalVar.Savefile.SaveFile_ControllerEmulation == EmulationType.Xbox360)
					{
						ExitDialog.BodyText.Text = LocalizationManager.Instance.GetValue("AppNotificationPopUp_DualsenseWillNotReadAsXbox");
					}
					else
					{
						ExitDialog.BodyText.Text = LocalizationManager.Instance.GetValue("AppNotificationPopUp_DualsenseWillNotReadAsDualShock4");
					}
					ExitDialog.PrimaryButtonText = LocalizationManager.Instance.GetValue("AppNotificationPopUp_Exit");
					ExitDialog.CloseButtonText = LocalizationManager.Instance.GetValue("AppNotificationPopUp_Cancel");
					((UIElement)ExitDialog.Rectangle2).Visibility = (Visibility)1;
					((FrameworkElement)ExitDialog.Rectangle1).Height = 0.0;
					((FrameworkElement)ExitDialog.Rectangle3).Height = 0.0;
					((FrameworkElement)ExitDialog.whatsnewTextblock).Height = 0.0;
					((FrameworkElement)ExitDialog.installNowTextblock).Height = 0.0;
					ExitDialog.ScrollViewer.HorizontalScrollBarVisibility = (ScrollBarVisibility)0;
					switch (await ExitDialog.ShowAsync())
					{
					case ContentDialogResult.Primary:
						((Control)HomePage_ConnectionStatus_ConnectionLabel).FontSize = 36.0;
						GLDT.HomePage_ConnectionStatus_ConnectionLabel_Content = "HomePage_ConnectionStatus_Status_ShuttingDownApp";
						path = null;
						dispatcherTimer.Stop();
						isAppClosing = true;
						((UIElement)App_TaskBarIcon).Visibility = (Visibility)1;
						connectedController.NormalTrigger(leftTrigger: false, rightTrigger: false, bothTriggers: true);
						connectedController.SetMicLedStatus(MicLED.OFF);
						connectedController.SetPlayerLedStatus(PlayerLED.AllOff, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED1, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED2, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED3, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED4, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED5);
						await Task.Delay(0);
						Application.Current.Shutdown();
						break;
					}
				}
			}
			else
			{
				if (App_TaskBarIcon != null)
				{
					((UIElement)App_TaskBarIcon).Visibility = (Visibility)1;
				}
				Application.Current.Shutdown();
			}
		}
		else
		{
			isAppClosing = true;
			((UIElement)App_TaskBarIcon).Visibility = (Visibility)1;
			Application.Current.Shutdown();
		}
	}

