	private async Task CheckForUpdates()
	{
		if (Directory.Exists("C:\\Temp\\DualSenseX\\Releases"))
		{
			using (UpdateManager manager = new UpdateManager("C:\\Temp\\DualSenseX\\Releases"))
			{
				await manager.UpdateApp();
			}
			return;
		}
		try
		{
			CreateTempDirectories();
			using UpdateManager manager = new UpdateManager("C:\\Temp\\DualSenseX\\Releases");
			await manager.UpdateApp();
		}
		catch (IOException)
		{
		}
	}

	private void CreateTempDirectories()
	{
		try
		{
			if (!Directory.Exists("C:\\Temp\\DualSenseX"))
			{
				Directory.CreateDirectory("C:\\Temp\\DualSenseX");
				Directory.CreateDirectory("C:\\Temp\\DualSenseX\\Releases");
			}
			if (!Directory.Exists("C:\\Temp\\DualSenseX\\Releases"))
			{
				Directory.CreateDirectory("C:\\Temp\\DualSenseX\\Releases");
			}
			if (!Directory.Exists("C:\\Temp\\DualSenseX\\Localization"))
			{
				Directory.CreateDirectory("C:\\Temp\\DualSenseX\\Localization");
			}
			File.WriteAllText("C:\\Temp\\DualSenseX\\DualSenseXLocation.txt", AppDomain.CurrentDomain.BaseDirectory);
		}
		catch (Exception ex)
		{
			Exception exp = ex;
			((DispatcherObject)this).Dispatcher.Invoke<Task>((Func<Task>)async delegate
			{
				if ((int)CustomMessageBox.ShowOKCancel("Oops an error occured!\n\n\n" + exp.Message, "DualSenseX", "Reset and Restart App", "Close App", (MessageBoxImage)48) == 1)
				{
					if (Directory.Exists("C:\\Temp\\DualSenseX"))
					{
						Directory.Delete("C:\\Temp\\DualSenseX", recursive: true);
						if (App_TaskBarIcon != null)
						{
							((UIElement)App_TaskBarIcon).Visibility = (Visibility)1;
						}
						await Task.Delay(2000);
						Application.Restart();
						Environment.Exit(0);
					}
				}
				else
				{
					if (App_TaskBarIcon != null)
					{
						((UIElement)App_TaskBarIcon).Visibility = (Visibility)1;
					}
					await Task.Delay(2000);
					Application.Current.Shutdown();
					Environment.Exit(0);
				}
			});
		}
	}

	private async void DownloadVersionInfoFromDrive()
	{
		if (CheckUpdateFromSettings)
		{
			new Icon(Application.GetResourceStream(MainIcon).Stream);
			new BitmapImage(MainIcon);
			string title = "DualSenseX";
			string message = "Checking For Updates...";
			App_TaskBarIcon.ShowBalloonTip(title, message, BalloonIcon.Info);
			await Task.Delay(3000);
			WebClient webClient = new WebClient();
			Uri address = new Uri("https://raw.githubusercontent.com/Paliverse/DualSenseX/main/Resources/_DualSenseXVersionNumber.txt");
			webClient.DownloadFileAsync(address, "C:\\Temp\\DualSenseX\\DualSenseXVersionNumber.txt");
			webClient.DownloadFileCompleted += FinishedDownloadingVersionInfoFromDrive;
		}
		else
		{
			WebClient webClient2 = new WebClient();
			Uri address2 = new Uri("https://raw.githubusercontent.com/Paliverse/DualSenseX/main/Resources/_DualSenseXVersionNumber.txt");
			webClient2.DownloadFileAsync(address2, "C:\\Temp\\DualSenseX\\DualSenseXVersionNumber.txt");
			webClient2.DownloadFileCompleted += FinishedDownloadingVersionInfoFromDrive;
		}
	}

	private async void FinishedDownloadingVersionInfoFromDrive(object sender, AsyncCompletedEventArgs e)
	{
		try
		{
			string assemblyFileVersion = GetAssemblyFileVersion();
			string text = "";
			List<string> list = new List<string>();
			Stream stream = OpenStream("C:\\Temp\\DualSenseX\\DualSenseXVersionNumber.txt");
			if (stream == null)
			{
				return;
			}
			if (stream.CanRead)
			{
				using StreamReader streamReader = new StreamReader(stream, Encoding.UTF8);
				string text2;
				while ((text2 = streamReader.ReadLine()) != null)
				{
					if (text == "")
					{
						text = Regex.Match(text2, "\\(([^)]*)\\)").Groups[1].Value;
					}
					else
					{
						list.Add(text2);
					}
				}
			}
			if (list == null)
			{
				return;
			}
			string text3 = string.Join("\n", list);
			if (text == "")
			{
				return;
			}
			Version version = new Version(assemblyFileVersion);
			Version value = new Version(text);
			int num = version.CompareTo(value);
			if (num > 0)
			{
				if (CheckUpdateFromSettings)
				{
					((DispatcherObject)this).Dispatcher.Invoke((Action)delegate
					{
						//IL_0011: Unknown result type (might be due to invalid IL or missing references)
						CustomMessageBox.ShowOK("App is running the latest Version.", "DualSenseX", "Okay", (MessageBoxImage)64);
					});
					CheckUpdateFromSettings = false;
					((UIElement)SettingsPage_CheckForUpdatesBtn).IsEnabled = true;
					App_TaskBarIcon.HideBalloonTip();
				}
				return;
			}
			if (num < 0)
			{
				ExitDialog.Hide();
				UpdateAvailabelDialog.Title = LocalizationManager.Instance.GetValue("AppNotificationPopUp_UpdateAvailable");
				UpdateAvailabelDialog.BodyText.Text = LocalizationManager.Instance.GetValue("AppNotificationPopUp_UpdateProccess_CurrentVersion") + assemblyFileVersion + "\n" + LocalizationManager.Instance.GetValue("AppNotificationPopUp_UpdateProccess_UpdateVersion") + text;
				UpdateAvailabelDialog.BodyText2.Text = text3 + "\n\n";
				((ContentControl)UpdateAvailabelDialog.installNowTextblock).Content = LocalizationManager.Instance.GetValue("AppNotificationPopUp_UpdateAvailable_InstallIt");
				UpdateAvailabelDialog.PrimaryButtonText = LocalizationManager.Instance.GetValue("AppNotificationPopUp_Yes");
				UpdateAvailabelDialog.SecondaryButtonText = LocalizationManager.Instance.GetValue("AppNotificationPopUp_Later");
				switch (await UpdateAvailabelDialog.ShowAsync())
				{
				case ContentDialogResult.Primary:
					DownloadLatestVersionFromDrive();
					break;
				case ContentDialogResult.Secondary:
					CheckUpdateFromSettings = false;
					((UIElement)SettingsPage_CheckForUpdatesBtn).IsEnabled = true;
					App_TaskBarIcon.HideBalloonTip();
					break;
				}
				return;
			}
			if (CheckUpdateFromSettings)
			{
				((DispatcherObject)this).Dispatcher.Invoke((Action)delegate
				{
					//IL_0011: Unknown result type (might be due to invalid IL or missing references)
					CustomMessageBox.ShowOK("App is running the latest Version.", "DualSenseX", "Okay", (MessageBoxImage)64);
				});
				CheckUpdateFromSettings = false;
				((UIElement)SettingsPage_CheckForUpdatesBtn).IsEnabled = true;
			}
			try
			{
				if (Directory.Exists("C:\\Temp\\DualSenseX\\Releases"))
				{
					Directory.Delete("C:\\Temp\\DualSenseX\\Releases", recursive: true);
					Directory.CreateDirectory("C:\\Temp\\DualSenseX\\Releases");
				}
			}
			catch (IOException)
			{
			}
		}
		catch (Exception)
		{
		}
	}

	private async void DownloadLatestVersionFromDrive()
	{
		_ = 1;
		try
		{
			WebClient client = new WebClient();
			Uri address = new Uri("https://github.com/Paliverse/DualSenseX/raw/main/Resources/Releases.zip");
			client.DownloadFileAsync(address, "C:\\Temp\\DualSenseX\\Releases.zip");
			client.DownloadProgressChanged += ProgressDownloadingLatestVersionFromDrive;
			client.DownloadFileCompleted += FinishedDownloadingLatestVersionFromDrive;
			if (((UIElement)DownloadLatesDialog).IsVisible)
			{
				return;
			}
			DownloadLatesDialog.Title = LocalizationManager.Instance.GetValue("AppNotificationPopUp_UpdateProccess_FetchingUpdate");
			((ContentControl)DownloadLatesDialog.PleaseWaitLabel).Content = LocalizationManager.Instance.GetValue("GamsPage_GameListStatusTwo_PleaseWait");
			DownloadLatesDialog.CloseButtonText = LocalizationManager.Instance.GetValue("AppNotificationPopUp_Cancel");
			((ContentControl)DownloadLatesDialog.ProgressValueLabel).Content = "0%";
			switch (await DownloadLatesDialog.ShowAsync())
			{
			case ContentDialogResult.Primary:
			{
				isAppUpdating = true;
				((Window)this).Hide();
				if (connectedController.IsControllerConnected())
				{
					path = null;
					dispatcherTimer.Stop();
					isAppClosing = true;
					connectedController.NormalTrigger(leftTrigger: false, rightTrigger: false, bothTriggers: true);
					connectedController.SetLedColorRGB(byte.MaxValue, byte.MaxValue, byte.MaxValue);
					connectedController.SetMicLedStatus(MicLED.OFF);
					connectedController.SetPlayerLedStatus(PlayerLED.AllOff, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED1, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED2, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED3, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED4, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED5);
				}
				((UIElement)App_TaskBarIcon).Visibility = (Visibility)1;
				string[] directories = Directory.GetDirectories(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData) + "\\DualSenseX");
				foreach (string text in directories)
				{
					if (text.Contains("DualSenseX.exe_Url"))
					{
						Directory.Delete(text, recursive: true);
					}
				}
				await Task.Delay(2000);
				Process.Start("C:\\Temp\\DualSenseX\\Releases\\Setup.exe");
				break;
			}
			default:
				IsLatestDownloadedCancelled = true;
				client.CancelAsync();
				client.Dispose();
				break;
			case ContentDialogResult.Secondary:
				break;
			}
		}
		catch (Exception)
		{
		}
	}

	private void ProgressDownloadingLatestVersionFromDrive(object sender, DownloadProgressChangedEventArgs e)
	{
		try
		{
			DownloadLatesDialog.Title = LocalizationManager.Instance.GetValue("AppNotificationPopUp_UpdateProccess_DownloadingUpdate");
			((RangeBase)DownloadLatesDialog.ProgressBar2).Value = e.ProgressPercentage;
			DownloadLatesDialog.BodyText.Text = e.BytesReceived.ToSize(MyExtension.SizeUnits.MB) + "/" + e.TotalBytesToReceive.ToSize(MyExtension.SizeUnits.MB) + " MB";
			((ContentControl)DownloadLatesDialog.ProgressValueLabel).Content = e.ProgressPercentage + "%";
		}
		catch (Exception)
		{
		}
	}

	private async void FinishedDownloadingLatestVersionFromDrive(object sender, AsyncCompletedEventArgs e)
	{
		_ = 1;
		try
		{
			await Task.Delay(2000);
			if (IsLatestDownloadedCancelled)
			{
				if (File.Exists("C:\\Temp\\DualSenseX\\Releases.zip"))
				{
					File.Delete("C:\\Temp\\DualSenseX\\Releases.zip");
					if (File.Exists("C:\\Temp\\DualSenseX\\Releases\\Setup.exe"))
					{
						File.Delete("C:\\Temp\\DualSenseX\\Releases\\Setup.exe");
					}
				}
				return;
			}
			DownloadLatesDialog.Title = LocalizationManager.Instance.GetValue("AppNotificationPopUp_UpdateProccess_ExtractingUpdate");
			UnZip("C:\\Temp\\DualSenseX\\Releases.zip", "C:\\Temp\\DualSenseX");
			await Task.Delay(2000);
			try
			{
				if (File.Exists("C:\\Temp\\DualSenseX\\Releases.zip"))
				{
					File.Delete("C:\\Temp\\DualSenseX\\Releases.zip");
					InstallUpdateAndRemoveFiles();
				}
			}
			catch (IOException)
			{
			}
		}
		catch (Exception)
		{
		}
	}

