	{
		GetAssemblyFileVersion();
		DownloadLatesDialog.Title = LocalizationManager.Instance.GetValue("AppNotificationPopUp_UpdateProccess_InstallingUpdate");
		await Task.Delay(3000);
		try
		{
			if (Directory.Exists("C:\\Temp\\DualSenseX\\Releases"))
