				DownloadLatesDialog.Title = LocalizationManager.Instance.GetValue("AppNotificationPopUp_UpdateProccess_UpdateInstalled");
				DownloadLatesDialog.BodyText.Text = LocalizationManager.Instance.GetValue("AppNotificationPopUp_UpdateProccess_PleaseRestartToApplyUpdate");
