				DownloadLatesDialog.PrimaryButtonText = LocalizationManager.Instance.GetValue("AppNotificationPopUp_UpdateProccess_Restart");
				((ContentControl)DownloadLatesDialog.ProgressValueLabel).Content = "";
				DownloadLatesDialog.DefaultButton = ContentDialogButton.Primary;
			}
		}
		catch (IOException)
		{
		}
	}

