	private static object OnCoerceScaleValue(DependencyObject o, object value)
	{
		if (o is Main main)
		{
			return main.OnCoerceScaleValue((double)value);
		}
		return value;
	}

	private static void OnScaleValueChanged(DependencyObject o, DependencyPropertyChangedEventArgs e)
	{
		if (o is Main main)
		{
			main.OnScaleValueChanged((double)((DependencyPropertyChangedEventArgs)(ref e)).OldValue, (double)((DependencyPropertyChangedEventArgs)(ref e)).NewValue);
		}
	}

	protected virtual double OnCoerceScaleValue(double value)
	{
		if (double.IsNaN(value))
		{
			return 1.0;
		}
		value = Math.Max(0.1, value);
		return value;
	}

	protected virtual void OnScaleValueChanged(double oldValue, double newValue)
	{
	}

	private void MainGrid_SizeChanged(object sender, EventArgs e)
	{
		CalculateScale();
	}

	private void CalculateScale()
	{
		double val = ((FrameworkElement)this).ActualWidth / 1920.0;
		double val2 = ((FrameworkElement)this).ActualHeight / 1080.0;
		double num = Math.Min(val, val2);
		ScaleValue = (double)OnCoerceScaleValue((DependencyObject)(object)MainGrid, num);
	}

