	public static bool IsWindowOpen<T>(string name = "") where T : Window
	{
		if (!string.IsNullOrEmpty(name))
		{
			return ((IEnumerable)Application.Current.Windows).OfType<T>().Any((T w) => ((FrameworkElement)(object)w).Name.Equals(name));
		}
		return ((IEnumerable)Application.Current.Windows).OfType<T>().Any();
	}

	public void CheckHidDevicesTimerFunc(object sender, EventArgs e)
	{
		CheckHidDevices();
	}

	public void CheckHidDevices()
	{
		HidDevice hidDeviceOrNull = DeviceList.Local.GetHidDeviceOrNull(1356, 3302);
		if (hidDeviceOrNull != null)
		{
			if (!GlobalVar.IsControllerConnectedStatus && !GlobalVar.DriverNotInstalled)
			{
				GlobalVar.DualSense = hidDeviceOrNull;
				GlobalVar.IsControllerConnectedStatus = true;
				connectedController.ConnectControllerEmulation();
			}
		}
		else if (GlobalVar.IsControllerConnectedStatus)
		{
			GlobalVar.IsControllerConnectedStatus = false;
			connectedController.DisconnectEmulationDevice();
			GlobalVar.DualSense = null;
			ranEnclosingMethod = false;
		}
		if (GlobalVar.IsControllerConnectedStatus && GlobalVar.DualSense != null && !ranEnclosingMethod)
		{
			TheEnclosingMethod();
		}
		CheckHidDevicesTimer.Stop();
		CheckHidDevicesTimer.Start();
	}

	public void ButtonPressedTimerFunc(object sender, EventArgs e)
	{
		ButtonPressedTimer();
	}

	public void ButtonPressedTimer()
	{
		if (GlobalVar.IsControllerConnectedStatus && GlobalVar.Savefile.SaveFile_OpenXboxGameBar && connectedController.MicButtonPressed() && connectedController.UpButtonPressed())
		{
			new InputSimulator().Keyboard.ModifiedKeyStroke(VirtualKeyCode.LWIN, VirtualKeyCode.VK_G);
		}
		ButtonPressesTimer.Stop();
		ButtonPressesTimer.Start();
	}

