			((ContentControl)GlobalVar.splashScreen.ConnectionStatusLabel).Content = ((ContentControl)HomePage_ConnectionStatus_ConnectionLabel).Content;
			((ContentControl)GlobalVar.splashScreen.StatusBatteryLevelIcon).Content = ((ContentControl)AppControllerStatusBatteryLevelIcon).Content;
			((ContentControl)GlobalVar.splashScreen.StatusBatteryLevelLabel).Content = ((ContentControl)AppControllerStatusBatteryLevelLabel).Content;
			((ContentControl)GlobalVar.splashScreen.EmulationTypeLabel).Content = ((ContentControl)HomePage_ConnectionStatus_EmulationTypeLabel).Content;
			if ((string)((ContentControl)GlobalVar.splashScreen.EmulationTypeLabel).Content == "")
			{
				((ContentControl)GlobalVar.splashScreen.ConnectionTypeLabel).Content = "";
				((ContentControl)GlobalVar.splashScreen.ActiveTriggerLabel).Content = "";
				((ContentControl)GlobalVar.splashScreen.ActiveTriggerStaticLabel).Content = "";
			}
			else
			{
				((ContentControl)GlobalVar.splashScreen.ActiveTriggerLabel).Content = ((ContentControl)(ComboBoxItem)((Selector)TriggerSelectionChangeComboBox).SelectedItem).Content.ToString();
				((ContentControl)GlobalVar.splashScreen.ActiveTriggerStaticLabel).Content = "Active Trigger";
				if (GlobalVar.DualSense != null)
				{
					if (GlobalVar.DualSense.GetMaxInputReportLength() == 78)
					{
						((ContentControl)GlobalVar.splashScreen.ConnectionTypeLabel).Content = "\ue702";
					}
					else if (GlobalVar.DualSense.GetMaxInputReportLength() == 64)
					{
						((ContentControl)GlobalVar.splashScreen.ConnectionTypeLabel).Content = "\uecf0";
					}
				}
			}
			if ((string)((ContentControl)HomePage_ConnectionStatus_EmulationTypeLabel).Content != "")
			{
				((UIElement)AppControllerConnectionTypeLabel).Visibility = (Visibility)0;
				((UIElement)AppControllerConnectionTypeLabel2).Visibility = (Visibility)0;
				if (GlobalVar.DualSense != null)
				{
					if (GlobalVar.DualSense.GetMaxInputReportLength() == 78)
					{
						((ContentControl)AppControllerConnectionTypeLabel).Content = "\ue702";
						((ContentControl)AppControllerConnectionTypeLabel2).Content = "\ue702";
					}
					else if (GlobalVar.DualSense.GetMaxInputReportLength() == 64)
					{
						((ContentControl)AppControllerConnectionTypeLabel).Content = "\uecf0";
						((ContentControl)AppControllerConnectionTypeLabel2).Content = "\uecf0";
					}
				}
			}
			else
			{
				((UIElement)AppControllerConnectionTypeLabel).Visibility = (Visibility)2;
				((ContentControl)AppControllerConnectionTypeLabel).Content = "";
				((UIElement)AppControllerConnectionTypeLabel2).Visibility = (Visibility)2;
				((ContentControl)AppControllerConnectionTypeLabel2).Content = "";
			}
			if (GlobalVar.IsControllerConnectedStatus)
			{
				if (PlaybackStream != null && PlaybackStream.PlaybackState == PlaybackState.Playing && GlobalVar.DidDefaultDeviceChange)
				{
					((UIElement)SettingsPage_RefreshoutputDevices).RaiseEvent(new RoutedEventArgs(ButtonBase.ClickEvent));
				}
				if (GlobalVar.EmulationChanged)
				{
					if (GlobalVar.Savefile.SaveFile_ControllerLEDColorMode == TouchpadColorMode.StaticColor)
					{
						Color saveFile_TouchpadLEDColor = GlobalVar.Savefile.SaveFile_TouchpadLEDColor;
						connectedController.SetLedColorRGB(((Color)(ref saveFile_TouchpadLEDColor)).R, ((Color)(ref saveFile_TouchpadLEDColor)).G, ((Color)(ref saveFile_TouchpadLEDColor)).B);
					}
					else if (GlobalVar.Savefile.SaveFile_ControllerLEDColorMode == TouchpadColorMode.Rainbow)
					{
						RainbowTimer.Stop();
						_r = byte.MaxValue;
						_g = 0;
						_b = 0;
						RainbowTimer = new DispatcherTimer();
						switch (GlobalVar.Savefile.SaveFile_RainbowSpeedMode)
						{
						case RainbowSpeedMode.Slow:
							RainbowTimer.Interval = TimeSpan.FromMilliseconds(0.001);
							break;
						case RainbowSpeedMode.Medium:
							RainbowTimer.Interval = TimeSpan.Zero;
							break;
						case RainbowSpeedMode.Fast:
							RainbowTimer.Interval = TimeSpan.Zero;
							break;
						case RainbowSpeedMode.Hyper:
							RainbowTimer.Interval = TimeSpan.Zero;
							break;
						default:
							RainbowTimer.Interval = TimeSpan.Zero;
							break;
						}
						RainbowTimer.Tick += RainbowTimerFunc;
						RainbowTimer.Start();
					}
					else if (GlobalVar.Savefile.SaveFile_ControllerLEDColorMode == TouchpadColorMode.Custom)
					{
						connectedController.SetLedColorRGB((byte)GlobalVar.Savefile.SaveFile_TouchpadLEDColorCustomR, (byte)GlobalVar.Savefile.SaveFile_TouchpadLEDColorCustomG, (byte)GlobalVar.Savefile.SaveFile_TouchpadLEDColorCustomB);
					}
					connectedController.TouchpadLEDBrightness(GlobalVar.Savefile.SaveFile_TouchpadLEDBrightness);
					connectedController.SetPlayerLedStatus(GlobalVar.Savefile.SaveFile_ControllerPLayerLED, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED1, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED2, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED3, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED4, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED5);
					connectedController.SetMicLedStatus(GlobalVar.Savefile.SaveFile_MicLED);
					connectedController.SetPlayerLedBrightness(GlobalVar.Savefile.SaveFile_PlayerLEDBrightness);
					GlobalVar.EmulationChanged = false;
				}
				((UIElement)ConnectToControllerBtn).IsEnabled = false;
				if (GlobalVar.DriverNotInstalled)
				{
					DisableUIElements();
				}
				connectedController.CheckConnection();
				Brush fill = (Brush)((TypeConverter)new BrushConverter()).ConvertFromString("#FF00C000");
				((Shape)AppControllerStatusEllipse).Fill = fill;
				((Shape)AppControllerStatusEllipse2).Fill = fill;
				if (connectedController.GetBatteryLevel() == 300)
