			{
				AttemptToReconnectToController();
				if (HomePage_ControllerModeGrid != null)
				{
					((FrameworkElement)HomePage_ControllerModeGrid).Height = 450.0;
				}
				if (HomePage_ControllerMode_TriggerSlectionGrid != null)
				{
					((FrameworkElement)HomePage_ControllerMode_TriggerSlectionGrid).Height = 200.0;
				}
				if (HomePage_ApplyModeGrid != null)
				{
					((FrameworkElement)HomePage_ApplyModeGrid).Height = 450.0;
				}
				if (HomePage_ApplyModeCheckBoxGrid != null)
				{
					((FrameworkElement)HomePage_ApplyModeCheckBoxGrid).Height = 120.0;
				}
				if (HomePage_ControllerMode_DockPanel1 != null)
				{
					((UIElement)HomePage_ControllerMode_DockPanel1).Visibility = (Visibility)0;
				}
				if (HomePage_ControllerMode_DockPanel2 != null)
				{
					((UIElement)HomePage_ControllerMode_DockPanel2).Visibility = (Visibility)2;
				}
				GlobalVar.ControllerLostConnection = false;
			}
		}
		catch (Exception)
		{
		}
	}

	private async void AttemptToReconnectToController()
	{
		if (PlaybackStream != null)
		{
			PlaybackStream.Stop();
			PlaybackStream.Dispose();
		}
		if (CaptureStream != null)
		{
			CaptureStream.Dispose();
		}
		await Task.Delay(1000);
		AutoConnectControllerRepeat = 1;
		AttemptToReconnectToControllerTimer = new DispatcherTimer();
		AttemptToReconnectToControllerTimer.Interval = new TimeSpan(0, 0, 1);
		AttemptToReconnectToControllerTimer.Tick += AttemptToReconnectToController;
		AttemptToReconnectToControllerTimer.Start();
	}

	private void AttemptToReconnectToController(object sender, EventArgs e)
	{
		RecconectToControllerAfterDisconnect();
	}

	private async void RecconectToControllerAfterDisconnect()
	{
		GlobalVar.ControllerLostConnection2 = true;
		if (GlobalVar.Savefile.SaveFile_AutoConnectSearchUntilConnected)
		{
			((ContentControl)AppNotificationLabel).Content = LocalizationManager.Instance.GetValue("AppNotificationLabel_ConnectionLost");
			((FrameworkElement)AppNotificationLabel).ToolTip = LocalizationManager.Instance.GetValue("AppNotificationLabel_ConnectionLost");
			if (GlobalVar.IsControllerConnectedStatus)
			{
				GlobalVar.ControllerLostConnection = false;
				GlobalVar.IsAppLaunched = false;
				AttemptToReconnectToControllerTimer.Stop();
				((ContentControl)AppNotificationLabel).Content = LocalizationManager.Instance.GetValue("AppNotificationLabel_ReconnectedToController");
				((FrameworkElement)AppNotificationLabel).ToolTip = LocalizationManager.Instance.GetValue("AppNotificationLabel_ReconnectedToController");
				if (GlobalVar.Savefile.SaveFile_DarkMode)
				{
					AppNotificationImage.Source = (ImageSource)new BitmapImage(InfoIcon_Light);
				}
				else
				{
					AppNotificationImage.Source = (ImageSource)new BitmapImage(InfoIcon_Dark);
				}
				((ContentControl)AppNotificationLabel).Content = "";
				((FrameworkElement)AppNotificationLabel).ToolTip = "";
				AppNotificationImage.Source = null;
			}
			else if (GlobalVar.DriverNotInstalled)
			{
				AttemptToReconnectToControllerTimer.Stop();
			}
			else
			{
				connectedController.Start();
				await Task.Delay(2000);
				TheEnclosingMethod();
			}
			return;
		}
		((ContentControl)AppNotificationLabel).Content = LocalizationManager.Instance.GetValue("AppNotificationLabel_ConnectionLostAttemptingToRconnect") + " (" + AutoConnectControllerRepeat + "/5)";
		((FrameworkElement)AppNotificationLabel).ToolTip = LocalizationManager.Instance.GetValue("AppNotificationLabel_ConnectionLostAttemptingToRconnect") + " (" + AutoConnectControllerRepeat + "/5)";
		if (GlobalVar.Savefile.SaveFile_DarkMode)
		{
			AppNotificationImage.Source = (ImageSource)new BitmapImage(InfoIcon_Light);
		}
		else
		{
			AppNotificationImage.Source = (ImageSource)new BitmapImage(InfoIcon_Dark);
		}
		if (AutoConnectControllerRepeat >= 6)
		{
			AttemptToReconnectToControllerTimer.Stop();
			TheEnclosingMethod();
			((ContentControl)AppNotificationLabel).Content = LocalizationManager.Instance.GetValue("AppNotificationLabel_FailedToRconnect");
			((FrameworkElement)AppNotificationLabel).ToolTip = LocalizationManager.Instance.GetValue("AppNotificationLabel_FailedToRconnect");
			if (GlobalVar.Savefile.SaveFile_DarkMode)
			{
				AppNotificationImage.Source = (ImageSource)new BitmapImage(InfoIcon_Light);
			}
			else
			{
				AppNotificationImage.Source = (ImageSource)new BitmapImage(InfoIcon_Dark);
			}
			((ContentControl)AppNotificationLabel).Content = "";
			AppNotificationImage.Source = null;
		}
		else if (GlobalVar.IsControllerConnectedStatus)
		{
			GlobalVar.ControllerLostConnection = false;
			GlobalVar.IsAppLaunched = false;
			AttemptToReconnectToControllerTimer.Stop();
			((ContentControl)AppNotificationLabel).Content = LocalizationManager.Instance.GetValue("AppNotificationLabel_ReconnectedToController");
			((FrameworkElement)AppNotificationLabel).ToolTip = LocalizationManager.Instance.GetValue("AppNotificationLabel_ReconnectedToController");
			if (GlobalVar.Savefile.SaveFile_DarkMode)
			{
				AppNotificationImage.Source = (ImageSource)new BitmapImage(InfoIcon_Light);
			}
			else
			{
				AppNotificationImage.Source = (ImageSource)new BitmapImage(InfoIcon_Dark);
			}
			((ContentControl)AppNotificationLabel).Content = "";
			((FrameworkElement)AppNotificationLabel).ToolTip = "";
			AppNotificationImage.Source = null;
		}
		else
		{
			connectedController.Start();
			await Task.Delay(2000);
			TheEnclosingMethod();
		}
		AutoConnectControllerRepeat++;
	}

