	private void UpdateTriggerModesFromUDPServer(int port)
	{
		UDPTask = Task.Run(delegate
		{
			UDPServer = new UdpClient(port);
			while (isUsingUDPServer)
			{
				try
				{
					IPEndPoint remoteEP = new IPEndPoint(IPAddress.Any, 0);
					byte[] bytes = UDPServer.Receive(ref remoteEP);
					string text = Encoding.ASCII.GetString(bytes);
					if (remoteEP.Address.Equals(GlobalVar.localhost))
					{
						Console.WriteLine("Recived '{0}' from {1}", text, remoteEP.Address.ToString());
						GlobalVar.Instruction[] instructions = GlobalVar.JsonToPacket(text).instructions;
						for (int i = 0; i < instructions.Length; i++)
						{
							GlobalVar.Instruction instruction = instructions[i];
							switch (instruction.type)
							{
							case GlobalVar.InstructionType.TriggerUpdate:
								HandleTriggerInstruction(instruction.parameters);
								break;
							case GlobalVar.InstructionType.RGBUpdate:
								HandleRGBInstruction(instruction.parameters);
								break;
							case GlobalVar.InstructionType.PlayerLED:
								HandlePlayerLedInstruction(instruction.parameters);
								break;
							case GlobalVar.InstructionType.TriggerThreshold:
								HandleTriggerThresholdInstruction(instruction.parameters);
								break;
							}
						}
					}
				}
				catch (Exception)
				{
				}
			}
		});
	}

	public void HandleTriggerThresholdInstruction(object[] parameters)
	{
		switch ((GlobalVar.Trigger)Convert.ToInt32(parameters[1]))
		{
		case GlobalVar.Trigger.Invalid:
			GlobalVar.Savefile.SaveFile_LeftTriggerThreshold = 0;
			GlobalVar.Savefile.SaveFile_RightTriggerThreshold = 0;
			break;
