		}
	}

	private async void DownloadLanguageListFromDrive(bool IsSetup)
	{
		try
		{
			DownloadLanguageListIsSetup = IsSetup;
			WebClient webClient = new WebClient();
			Uri address = new Uri("https://raw.githubusercontent.com/Paliverse/DualSenseX/main/Resources/_LanguagesList.txt");
			webClient.DownloadFileAsync(address, "C:\\Temp\\DualSenseX\\Localization\\LanguageList.txt");
			webClient.DownloadFileCompleted += FinishedDownloadingLanguageListFromDrive;
		}
		catch (Exception)
		{
		}
	}

