	private void SetupScreen_LangaugesList_SelectionChanged(object sender, SelectionChangedEventArgs e)
	{
		List<CultureInfo> availableCultures = LocalizationManager.Instance.AvailableCultures;
		LanguageListComboBox languageListComboBox = (LanguageListComboBox)((Selector)SetupScreen_LangaugesList).SelectedItem;
		((Selector)SettingsPage_LangaugesList).SelectedItem = languageListComboBox;
		foreach (CultureInfo item in availableCultures)
		{
			if (item.EnglishName == languageListComboBox.LanguageName)
			{
				LocalizationManager.Instance.CurrentCulture = item;
			}
		}
	}

	private void SettingsPage_LangaugesList_SelectionChanged(object sender, SelectionChangedEventArgs e)
	{
		List<CultureInfo> availableCultures = LocalizationManager.Instance.AvailableCultures;
		LanguageListComboBox languageListComboBox = (LanguageListComboBox)((Selector)SettingsPage_LangaugesList).SelectedItem;
		foreach (CultureInfo item in availableCultures)
		{
			if (item.EnglishName == languageListComboBox.LanguageName)
			{
				LocalizationManager.Instance.CurrentCulture = item;
				LocalizationManager.Instance.Refresh();
				GlobalVar.Savefile.SaveFile_Language = languageListComboBox.LanguageName;
				SaveSettingsINI();
				RefreshTranslationLabels();
			}
		}
	}

