			_g = 0;
			_b = 0;
			RainbowTimer = new DispatcherTimer();
			switch (GlobalVar.Savefile.SaveFile_RainbowSpeedMode)
			{
			case RainbowSpeedMode.Slow:
				RainbowTimer.Interval = TimeSpan.FromMilliseconds(0.001);
				break;
			case RainbowSpeedMode.Medium:
				RainbowTimer.Interval = TimeSpan.Zero;
				break;
			case RainbowSpeedMode.Fast:
				RainbowTimer.Interval = TimeSpan.Zero;
				break;
			case RainbowSpeedMode.Hyper:
				RainbowTimer.Interval = TimeSpan.Zero;
				break;
			default:
				RainbowTimer.Interval = TimeSpan.Zero;
				break;
			}
			RainbowTimer.Tick += RainbowTimerFunc;
			RainbowTimer.Start();
		}
		else if (((Selector)HomePage_TouchpadLedColorMode).SelectedIndex == 2)
		{
			((FrameworkElement)HomePage_TouchpadLedColorMode).Width = 100.0;
			((UIElement)HomePage_TouchpadLedManyColorsStack).Visibility = (Visibility)2;
			((UIElement)HomePage_TouchpadLedCustomColorStack).Visibility = (Visibility)0;
