	private void PlayerLedBatteryLevelTimerFunc(object sender, EventArgs e)
	{
		PlayerLedBatteryLevelTimerFunc2();
	}

	private async void PlayerLedBatteryLevelTimerFunc2()
	{
		if (GlobalVar.Savefile.SaveFile_ControllerPLayerLED == PlayerLED.BatteryLevel)
		{
			if (!GlobalVar.IsControllerConnectedStatus)
			{
				return;
			}
			if (GlobalVar.Savefile.SaveFile_PlayerLed_FlashWhileCharging)
			{
				if (connectedController.dualSenseUpdated.isCharging)
				{
					if (connectedController.GetBatteryLevel() >= 0 && connectedController.GetBatteryLevel() <= 20)
					{
						connectedController.SetPlayerLedStatus(PlayerLED.Custom, checkbox1: true, checkbox2: false, checkbox3: false, checkbox4: false, checkbox5: false);
						await Task.Delay(1000);
						connectedController.SetPlayerLedStatus(PlayerLED.Custom, checkbox1: false, checkbox2: false, checkbox3: false, checkbox4: false, checkbox5: false);
					}
					else if (connectedController.GetBatteryLevel() >= 20 && connectedController.GetBatteryLevel() <= 40)
					{
						connectedController.SetPlayerLedStatus(PlayerLED.Custom, checkbox1: true, checkbox2: true, checkbox3: false, checkbox4: false, checkbox5: false);
						await Task.Delay(1000);
						connectedController.SetPlayerLedStatus(PlayerLED.Custom, checkbox1: true, checkbox2: false, checkbox3: false, checkbox4: false, checkbox5: false);
					}
					else if (connectedController.GetBatteryLevel() >= 40 && connectedController.GetBatteryLevel() <= 60)
					{
						connectedController.SetPlayerLedStatus(PlayerLED.Custom, checkbox1: true, checkbox2: true, checkbox3: true, checkbox4: false, checkbox5: false);
						await Task.Delay(1000);
						connectedController.SetPlayerLedStatus(PlayerLED.Custom, checkbox1: true, checkbox2: true, checkbox3: false, checkbox4: false, checkbox5: false);
					}
					else if (connectedController.GetBatteryLevel() >= 60 && connectedController.GetBatteryLevel() <= 80)
					{
