					{
						connectedController.SetPlayerLedStatus(PlayerLED.Custom, checkbox1: true, checkbox2: true, checkbox3: true, checkbox4: true, checkbox5: true);
						await Task.Delay(1000);
						connectedController.SetPlayerLedStatus(PlayerLED.Custom, checkbox1: true, checkbox2: true, checkbox3: true, checkbox4: true, checkbox5: false);
					}
				}
				else if (connectedController.GetBatteryLevel() >= 0 && connectedController.GetBatteryLevel() <= 20)
				{
					connectedController.SetPlayerLedStatus(PlayerLED.Custom, checkbox1: true, checkbox2: false, checkbox3: false, checkbox4: false, checkbox5: false);
