	private void HomePage_ControllerMode_CustomTriggerValue_InfoBtn_Click(object sender, RoutedEventArgs e)
	{
		((DispatcherObject)this).Dispatcher.Invoke((Action)delegate
		{
			//IL_0010: Unknown result type (might be due to invalid IL or missing references)
			CustomMessageBox.ShowOK("About mode and forces\n\n● Mode - The mode to apply for trigger\n\n● Force 1 - Start of resistance\n\n● Force 2 - Amount of force exerted\n\n● Force 3 - Force exerted in range\n\n● Force 4 - Strength of effect near release state (requires modes Rigid AB or Pulse AB)\n\n● Force 5 - Strength of effect near middle (requires modes Rigid AB or Pulse AB)\n\n● Force 6 - Strength of effect at pressed state (requires modes Rigid AB or Pulse AB)\n\n● Force 7 - Effect actuation frequency in Hz (requires modes Rigid AB or Pulse AB)", "DualSenseX", "Okay", (MessageBoxImage)0);
		});
	}

