	private void LeftTriggerCheckBox_Checked(object sender, RoutedEventArgs e)
	{
		((ToggleButton)LeftTriggerCheckBox).IsChecked = true;
		if (((ToggleButton)RightTriggerCheckBox).IsChecked == true || ((ToggleButton)BothTriggerCheckBox).IsChecked == true)
		{
			((ToggleButton)RightTriggerCheckBox).IsChecked = false;
			((ToggleButton)BothTriggerCheckBox).IsChecked = false;
		}
	}

	private void RightTriggerCheckBox_Checked(object sender, RoutedEventArgs e)
	{
		((ToggleButton)RightTriggerCheckBox).IsChecked = true;
		if (((ToggleButton)LeftTriggerCheckBox).IsChecked == true || ((ToggleButton)BothTriggerCheckBox).IsChecked == true)
		{
			((ToggleButton)LeftTriggerCheckBox).IsChecked = false;
			((ToggleButton)BothTriggerCheckBox).IsChecked = false;
		}
	}

	private void BothTriggerCheckBox_Checked(object sender, RoutedEventArgs e)
	{
		((ToggleButton)BothTriggerCheckBox).IsChecked = true;
