			((ToggleButton)RightTriggerCheckBox).IsChecked = false;
		}
	}

	private CustomTriggerValueMode GetCustomTriggerModeValueFromComboBox(string name)
	{
		return name switch
		{
			"OFF" => CustomTriggerValueMode.OFF, 
			"Rigid" => CustomTriggerValueMode.Rigid, 
			"Rigid A" => CustomTriggerValueMode.RigidA, 
			"Rigid B" => CustomTriggerValueMode.RigidB, 
			"Rigid AB" => CustomTriggerValueMode.RigidAB, 
			"Pulse" => CustomTriggerValueMode.Pulse, 
			"Pulse A" => CustomTriggerValueMode.PulseA, 
			"Pulse B" => CustomTriggerValueMode.PulseB, 
			"Pulse AB" => CustomTriggerValueMode.PulseAB, 
			"VibrateResistance" => CustomTriggerValueMode.VibrateResistance, 
			"VibrateResistance A" => CustomTriggerValueMode.VibratePulseA, 
			"VibrateResistance B" => CustomTriggerValueMode.VibratePulsB, 
			"VibrateResistance AB" => CustomTriggerValueMode.VibrateResistanceAB, 
			"Vibrate Pulse" => CustomTriggerValueMode.VibratePulse, 
			"Vibrate Pulse A" => CustomTriggerValueMode.VibratePulseA, 
			"Vibrate Pulse B" => CustomTriggerValueMode.VibratePulsB, 
			"Vibrate Pulse AB" => CustomTriggerValueMode.VibratePulseAB, 
			_ => CustomTriggerValueMode.OFF, 
		};
	}

