	private void SliderValueChange_ValueChanged(object sender, RoutedPropertyChangedEventArgs<double> e)
	{
		//IL_0018: Unknown result type (might be due to invalid IL or missing references)
		//IL_0062: Unknown result type (might be due to invalid IL or missing references)
		int num = (int)((RangeBase)SliderValueChange).Value;
		if (((ContentControl)(ComboBoxItem)((Selector)TriggerSelectionChangeComboBox).SelectedItem).Content.ToString() == "Vibrate Trigger Custom Intensity")
		{
			if (num >= 40)
			{
				((UIElement)HomePage_ControllerMode_WarningStackPanel).Visibility = (Visibility)0;
			}
			else if (num < 40)
			{
				((UIElement)HomePage_ControllerMode_WarningStackPanel).Visibility = (Visibility)1;
			}
		}
		else if (((ContentControl)(ComboBoxItem)((Selector)TriggerSelectionChangeComboBox).SelectedItem).Content.ToString() == "Vibrate Trigger Pulse")
		{
			((UIElement)HomePage_ControllerMode_WarningStackPanel).Visibility = (Visibility)0;
		}
		else
		{
			((UIElement)HomePage_ControllerMode_WarningStackPanel).Visibility = (Visibility)1;
		}
	}

	private void VibrateControllerDispatcherTimer_Tick(object sender, EventArgs e)
	{
		VibrationControllerTimer();
	}

	private void VibrationControllerTimer()
	{
		if (VibrationDurationTimer >= VibrateDuration)
		{
			connectedController.ControllerVibration(((ToggleButton)LeftTriggerCheckBox).IsChecked.Value, ((ToggleButton)RightTriggerCheckBox).IsChecked.Value, ((ToggleButton)BothTriggerCheckBox).IsChecked.Value, 0);
			dispatcherTimer.Stop();
			((UIElement)ApplyControllerSettings).IsEnabled = true;
		}
		else
		{
			double value = ((RangeBase)SliderValueChange).Value;
