	private void DownloadGamesListFromDrive()
	{
		try
		{
			((ItemsControl)GamesPage_GamesListView).ItemsSource = null;
			CollectionViewSource.GetDefaultView((object)GamesPageGamesList).Refresh();
			((UIElement)GamesPage_SelectedGameGrid).Visibility = (Visibility)1;
