			((UIElement)GamesPage_GameListStatusStackPanel).Opacity = 1.0;
			WebClient webClient = new WebClient();
			Uri address = new Uri("https://raw.githubusercontent.com/Paliverse/DualSenseX/main/Resources/_GamesList.xml");
			webClient.DownloadFileAsync(address, "C:\\Temp\\DualSenseX\\GamesList.xml");
			webClient.DownloadFileCompleted += FinishedDownloadingGamesListFromDrive;
		}
		catch (Exception)
		{
		}
	}

