	private void LoadGamesPageList()
	{
		//IL_0019: Unknown result type (might be due to invalid IL or missing references)
		//IL_001f: Expected O, but got Unknown
		//IL_005f: Unknown result type (might be due to invalid IL or missing references)
		//IL_0064: Unknown result type (might be due to invalid IL or missing references)
		//IL_0070: Unknown result type (might be due to invalid IL or missing references)
		if (File.Exists("C:\\temp\\DualSenseX\\GamesList.xml"))
		{
			try
			{
				XmlSerializer val = new XmlSerializer(typeof(List<GamePageGamesList>));
				using FileStream fileStream = File.OpenRead("C:\\temp\\DualSenseX\\GamesList.xml");
				List<GamePageGamesList> list = (GamesPageGamesList = (List<GamePageGamesList>)val.Deserialize((Stream)fileStream));
				((ItemsControl)GamesPage_GamesListView).ItemsSource = GamesPageGamesList;
				CollectionView val2 = (CollectionView)CollectionViewSource.GetDefaultView((object)((ItemsControl)GamesPage_GamesListView).ItemsSource);
				((Collection<SortDescription>)(object)val2.SortDescriptions).Add(new SortDescription("GameName", ListSortDirection.Ascending));
				val2.Filter = UserFilter;
				List<string> list2 = new List<string>();
				foreach (GamePageGamesList item in list)
				{
					foreach (string gamesPage_Tag in item.GamesPage_Tags)
					{
						list2.Add(gamesPage_Tag);
					}
					string gamesPage_TagsJoinedString = string.Join(", ", list2);
					item.GamesPage_TagsJoinedString = gamesPage_TagsJoinedString;
					list2.Clear();
				}
				if (GamesPageGamesList.Count >= 1)
				{
					((Selector)GamesPage_GamesListView).SelectedIndex = 0;
					((UIElement)GamesPage_SelectedGameGrid).Visibility = (Visibility)0;
					((ContentControl)GamesPage_GameListStatusLabel1).Content = "";
					((ContentControl)GamesPage_GameListStatusLabel2).Content = "";
					((UIElement)GamesPage_GameListStatusStackPanel).Opacity = 0.0;
				}
				else
				{
					((UIElement)GamesPage_SelectedGameGrid).Visibility = (Visibility)1;
					((ContentControl)GamesPage_GameListStatusLabel1).Content = LocalizationManager.Instance.GetValue("GamsPage_GameListStatusOne");
					((ContentControl)GamesPage_GameListStatusLabel2).Content = LocalizationManager.Instance.GetValue("GamsPage_GameListStatusTwo");
					((UIElement)GamesPage_GameListStatusStackPanel).Opacity = 1.0;
				}
				return;
			}
			catch (Exception)
			{
				return;
			}
		}
		SaveGamesPageList(isGenerating: false);
	}

	private bool UserFilter(object item)
	{
		if (string.IsNullOrEmpty(GamesPage_SearchGamesTextBox.Text))
		{
			return true;
		}
		if ((item as GamePageGamesList).GameName.IndexOf(GamesPage_SearchGamesTextBox.Text, StringComparison.OrdinalIgnoreCase) < 0)
		{
			return (item as GamePageGamesList).GamesPage_TagsJoinedString.IndexOf(GamesPage_SearchGamesTextBox.Text, StringComparison.OrdinalIgnoreCase) >= 0;
		}
		return true;
	}

