	private async void ShowOverlay(GlobalVar.OverlayPos ScreenPos, int DelayUntilClose, bool StayActive)
	{
		Rect workArea = SystemParameters.WorkArea;
		double primaryScreenWidth = SystemParameters.PrimaryScreenWidth;
		double primaryScreenHeight = SystemParameters.PrimaryScreenHeight;
		TriggerInfoWindow splashScreen = new TriggerInfoWindow();
		HideOverlay();
		GlobalVar.splashScreen = splashScreen;
		((ContentControl)GlobalVar.splashScreen.ConnectionStatusLabel).Content = ((ContentControl)HomePage_ConnectionStatus_ConnectionLabel).Content;
		((ContentControl)GlobalVar.splashScreen.StatusBatteryLevelIcon).Content = ((ContentControl)AppControllerStatusBatteryLevelIcon).Content;
		((ContentControl)GlobalVar.splashScreen.StatusBatteryLevelLabel).Content = ((ContentControl)AppControllerStatusBatteryLevelLabel).Content;
		if (connectedController.ConnectionType == "Bluetooth")
		{
			((ContentControl)GlobalVar.splashScreen.ConnectionTypeLabel).Content = "\ue702";
		}
		else
		{
			((ContentControl)GlobalVar.splashScreen.ConnectionTypeLabel).Content = "\uecf0";
		}
		((ContentControl)GlobalVar.splashScreen.EmulationTypeLabel).Content = ((ContentControl)HomePage_ConnectionStatus_EmulationTypeLabel).Content;
		((ContentControl)GlobalVar.splashScreen.ActiveTriggerLabel).Content = ((ContentControl)(ComboBoxItem)((Selector)TriggerSelectionChangeComboBox).SelectedItem).Content.ToString();
		GlobalVar.overlayPosVar = ScreenPos;
		switch (ScreenPos)
		{
		case GlobalVar.OverlayPos.Center:
			((Window)GlobalVar.splashScreen).WindowStartupLocation = (WindowStartupLocation)1;
			break;
		case GlobalVar.OverlayPos.TopRight:
			((Window)GlobalVar.splashScreen).Left = ((Rect)(ref workArea)).Right - ((FrameworkElement)GlobalVar.splashScreen).Width;
			((Window)GlobalVar.splashScreen).Top = ((Rect)(ref workArea)).Top;
			break;
		case GlobalVar.OverlayPos.TopLeft:
			((Window)GlobalVar.splashScreen).Left = ((Rect)(ref workArea)).Left;
			((Window)GlobalVar.splashScreen).Top = ((Rect)(ref workArea)).Top;
			break;
		case GlobalVar.OverlayPos.BottomRight:
			((Window)GlobalVar.splashScreen).Left = ((Rect)(ref workArea)).Right - ((FrameworkElement)GlobalVar.splashScreen).Width;
			((Window)GlobalVar.splashScreen).Top = ((Rect)(ref workArea)).Bottom - ((FrameworkElement)GlobalVar.splashScreen).Height;
			break;
		case GlobalVar.OverlayPos.BottomLeft:
			((Window)GlobalVar.splashScreen).Left = ((Rect)(ref workArea)).Left;
			((Window)GlobalVar.splashScreen).Top = ((Rect)(ref workArea)).Bottom - ((FrameworkElement)GlobalVar.splashScreen).Height;
			break;
		case GlobalVar.OverlayPos.TopCenter:
			((Window)GlobalVar.splashScreen).Left = primaryScreenWidth / 2.0 - ((FrameworkElement)GlobalVar.splashScreen).Width / 2.0;
			((Window)GlobalVar.splashScreen).Top = ((Rect)(ref workArea)).Top;
			break;
		case GlobalVar.OverlayPos.BottomCenter:
			((Window)GlobalVar.splashScreen).Left = primaryScreenWidth / 2.0 - ((FrameworkElement)GlobalVar.splashScreen).Width / 2.0;
			((Window)GlobalVar.splashScreen).Top = ((Rect)(ref workArea)).Bottom - ((FrameworkElement)GlobalVar.splashScreen).Height;
			break;
		case GlobalVar.OverlayPos.LeftCenter:
			((Window)GlobalVar.splashScreen).Left = ((Rect)(ref workArea)).Left;
			((Window)GlobalVar.splashScreen).Top = primaryScreenHeight / 2.0 - ((FrameworkElement)GlobalVar.splashScreen).Height / 2.0;
			break;
		case GlobalVar.OverlayPos.RightCenter:
			((Window)GlobalVar.splashScreen).Left = ((Rect)(ref workArea)).Right - ((FrameworkElement)GlobalVar.splashScreen).Width;
			((Window)GlobalVar.splashScreen).Top = primaryScreenHeight / 2.0 - ((FrameworkElement)GlobalVar.splashScreen).Height / 2.0;
			break;
		}
		((UIElement)GlobalVar.splashScreen.InitialGrid).Visibility = (Visibility)1;
		((Window)GlobalVar.splashScreen).Show();
		await Task.Delay(200);
		((UIElement)GlobalVar.splashScreen.InitialGrid).Visibility = (Visibility)0;
		GlobalVar.splashScreen.EnableBlur();
		UpdateOverlayOffset();
		if (!StayActive)
		{
			await Task.Delay(DelayUntilClose);
			((UIElement)GlobalVar.splashScreen.InitialGrid).Visibility = (Visibility)1;
			await Task.Delay(250);
			((Window)GlobalVar.splashScreen).Close();
		}
	}

