	private void Sense2KeyPage_DeleteProfileBtn_Click(object sender, RoutedEventArgs e)
	{
		if (((Selector)Sense2KeyPage_ListView).SelectedItem != null)
		{
			Sense2KeyProfileList.Remove((Sense2KeyProfiles)((Selector)Sense2KeyPage_ListView).SelectedItem);
			CollectionViewSource.GetDefaultView((object)Sense2KeyProfileList).Refresh();
			((Selector)Sense2KeyPage_ListView).SelectedIndex = 0;
			if (Sense2KeyProfileList.Count >= 1)
			{
				((Selector)Sense2KeyPage_ListView).SelectedIndex = 0;
				((UIElement)Sense2Key_NoProfilesStackPanel).Visibility = (Visibility)1;
				((UIElement)Sense2Key_Selected_NoProfilesStackPanel).Visibility = (Visibility)1;
				((UIElement)Sense2Key_SelectedProfileGrid).Visibility = (Visibility)0;
				((UIElement)Sense2Key_Selected_ProfileStatusBorder).Visibility = (Visibility)0;
			}
			else
			{
				((UIElement)Sense2Key_NoProfilesStackPanel).Visibility = (Visibility)0;
				((UIElement)Sense2Key_Selected_NoProfilesStackPanel).Visibility = (Visibility)0;
				((UIElement)Sense2Key_SelectedProfileGrid).Visibility = (Visibility)1;
				((UIElement)Sense2Key_Selected_ProfileStatusBorder).Visibility = (Visibility)1;
			}
			SaveSense2KeyProfiles();
		}
	}

