	private void Sense2KeyPage_Selected_ExportBtn_Click(object sender, RoutedEventArgs e)
	{
		//IL_00d4: Unknown result type (might be due to invalid IL or missing references)
		//IL_0027: Unknown result type (might be due to invalid IL or missing references)
		//IL_002d: Expected O, but got Unknown
		//IL_0090: Unknown result type (might be due to invalid IL or missing references)
		try
		{
			if (SelectedSense2KeyProfile != null)
			{
				Sense2KeyProfileExportImportList.Clear();
				Sense2KeyProfileExportImportList.Add(SelectedSense2KeyProfile);
				SaveFileDialog val = new SaveFileDialog();
				((FileDialog)val).InitialDirectory = "C:\\temp\\DualSenseX\\";
				((FileDialog)val).Filter = "XML-File | *.xml";
				((FileDialog)val).FileName = "Sense2KeyProfile_" + Sense2KeyProfileExportImportList[0].ProfileName + ".xml";
				if (((CommonDialog)val).ShowDialog() == true)
				{
					XmlSerializer val2 = new XmlSerializer(typeof(List<Sense2KeyProfiles>));
					TextWriter textWriter = new StreamWriter(((FileDialog)val).FileName);
					val2.Serialize(textWriter, (object)Sense2KeyProfileExportImportList);
					textWriter.Close();
				}
			}
		}
		catch (Exception ex)
		{
			CustomMessageBox.ShowOK("Oops an error occured!\n\n\n" + ex.Message, "DualSenseX", "Okay", (MessageBoxImage)48);
		}
	}

	private async void Sense2KeyPage_ImportProfileBtn_Click(object sender, RoutedEventArgs e)
	{
		Sense2KeyProfileExportImportList.Clear();
		OpenFileDialog val = new OpenFileDialog();
		((FileDialog)val).Filter = "XML-File | *.xml";
		((FileDialog)val).InitialDirectory = GetDownloadsPath();
		if (((CommonDialog)val).ShowDialog() != true)
		{
			return;
		}
		string fileName = ((FileDialog)val).FileName;
		XmlSerializer val2 = new XmlSerializer(typeof(List<Sense2KeyProfiles>));
		if (!File.Exists(fileName))
		{
			return;
		}
		try
		{
			using FileStream stream = File.OpenRead(fileName);
			List<Sense2KeyProfiles> dezerializedList = (List<Sense2KeyProfiles>)val2.Deserialize((Stream)stream);
			List<string> valStrings = new List<string>();
			foreach (Sense2KeyProfiles sense2KeyProfile in Sense2KeyProfileList)
			{
				valStrings.Add(sense2KeyProfile.ProfileName);
			}
			await Task.Delay(200);
			if (!valStrings.Contains(dezerializedList[0].ProfileName))
			{
				Sense2KeyProfileList.Add(dezerializedList[0]);
				SaveSense2KeyProfiles();
				CollectionViewSource.GetDefaultView((object)Sense2KeyProfileList).Refresh();
				Sense2KeyProfileExportImportList.Clear();
				BrushConverter val3 = new BrushConverter();
				Brush foreground = (Brush)((TypeConverter)(object)val3).ConvertFromString("#FF88E188");
				Brush redColor = (Brush)((TypeConverter)(object)val3).ConvertFromString("#FFFF5148");
				((UIElement)Sense2Key_Selected_NewProfileErrorBorder).Opacity = 1.0;
				((Control)Sense2Key_Selected_NewProfileErrorLabel).Foreground = foreground;
				((ContentControl)Sense2Key_Selected_NewProfileErrorLabel).Content = LocalizationManager.Instance.GetValue("Sense2Key_ProfileStatus_ProfileCreated");
				await Task.Delay(5000);
				((UIElement)Sense2Key_Selected_NewProfileErrorBorder).Opacity = 0.0;
				((ContentControl)Sense2Key_Selected_NewProfileErrorLabel).Content = "";
				((Control)Sense2Key_Selected_NewProfileErrorLabel).Foreground = redColor;
			}
			else
			{
				((UIElement)Sense2Key_Selected_NewProfileErrorBorder).Opacity = 1.0;
				((ContentControl)Sense2Key_Selected_NewProfileErrorLabel).Content = LocalizationManager.Instance.GetValue("Sense2Key_ProfileStatus_ProfileExists");
				await Task.Delay(5000);
				((UIElement)Sense2Key_Selected_NewProfileErrorBorder).Opacity = 0.0;
				((ContentControl)Sense2Key_Selected_NewProfileErrorLabel).Content = "";
			}
		}
		catch (Exception)
		{
		}
	}

	public static string GetDownloadsPath()
	{
		if (Environment.OSVersion.Version.Major >= 6 && SHGetKnownFolderPath(ref FolderDownloads, 0, IntPtr.Zero, out var ptr) == 0)
		{
			string? result = Marshal.PtrToStringUni(ptr);
			Marshal.FreeCoTaskMem(ptr);
			return result;
		}
		return Path.Combine(Path.GetDirectoryName(Environment.GetFolderPath(Environment.SpecialFolder.Personal)), "Downloads");
	}

	[DllImport("shell32.dll", CharSet = CharSet.Auto)]
	private static extern int SHGetKnownFolderPath(ref Guid id, int flags, IntPtr token, out IntPtr path);

