	private async void Sense2Key_Selected_UpdateNameBtn_Click(object sender, RoutedEventArgs e)
	{
		int i = 0;
		try
		{
			foreach (Sense2KeyProfiles profiles in Sense2KeyProfileList)
			{
				if (SelectedSense2KeyProfile.ProfileName == profiles.ProfileName)
				{
					if (Sense2Key_Selected_ProfileNameTextbox.Text != "")
					{
						List<string> valStrings = new List<string>();
						foreach (Sense2KeyProfiles sense2KeyProfile in Sense2KeyProfileList)
						{
							valStrings.Add(sense2KeyProfile.ProfileName);
						}
						await Task.Delay(200);
						if (!valStrings.Contains(Sense2Key_Selected_ProfileNameTextbox.Text))
						{
							profiles.ProfileName = Sense2Key_Selected_ProfileNameTextbox.Text;
							SaveSense2KeyProfiles();
							((ItemsControl)Sense2KeyPage_ListView).ItemsSource = Sense2KeyProfileList;
							CollectionViewSource.GetDefaultView((object)Sense2KeyProfileList).Refresh();
							((ListBox)Sense2KeyPage_ListView).UnselectAll();
							((Selector)Sense2KeyPage_ListView).SelectedIndex = i;
							BrushConverter val = new BrushConverter();
							Brush foreground = (Brush)((TypeConverter)(object)val).ConvertFromString("#FF88E188");
							Brush redColor = (Brush)((TypeConverter)(object)val).ConvertFromString("#FFFF5148");
							((UIElement)Sense2Key_Selected_NewProfileErrorBorder).Opacity = 1.0;
							((Control)Sense2Key_Selected_NewProfileErrorLabel).Foreground = foreground;
							((ContentControl)Sense2Key_Selected_NewProfileErrorLabel).Content = LocalizationManager.Instance.GetValue("Sense2Key_ProfileStatus_ProfileNameUpdated");
							await Task.Delay(5000);
							((UIElement)Sense2Key_Selected_NewProfileErrorBorder).Opacity = 0.0;
							((ContentControl)Sense2Key_Selected_NewProfileErrorLabel).Content = "";
							((Control)Sense2Key_Selected_NewProfileErrorLabel).Foreground = redColor;
						}
						else
						{
							((UIElement)Sense2Key_Selected_NewProfileErrorBorder).Opacity = 1.0;
							((ContentControl)Sense2Key_Selected_NewProfileErrorLabel).Content = LocalizationManager.Instance.GetValue("Sense2Key_ProfileStatus_ProfileExists");
							await Task.Delay(5000);
							((UIElement)Sense2Key_Selected_NewProfileErrorBorder).Opacity = 0.0;
							((ContentControl)Sense2Key_Selected_NewProfileErrorLabel).Content = "";
						}
					}
					else
					{
						((UIElement)Sense2Key_Selected_NewProfileErrorBorder).Opacity = 1.0;
						((ContentControl)Sense2Key_Selected_NewProfileErrorLabel).Content = LocalizationManager.Instance.GetValue("Sense2Key_ProfileStatus_ProfileNameCantBeEmpty");
						await Task.Delay(5000);
						((UIElement)Sense2Key_Selected_NewProfileErrorBorder).Opacity = 0.0;
						((ContentControl)Sense2Key_Selected_NewProfileErrorLabel).Content = "";
					}
				}
				i++;
			}
		}
		catch (Exception)
		{
		}
	}

