	private void SettingsPage_ResetAppBtn_Click(object sender, RoutedEventArgs e)
	{
		((DispatcherObject)this).Dispatcher.Invoke<Task>((Func<Task>)async delegate
		{
			if ((int)CustomMessageBox.ShowOKCancel(LocalizationManager.Instance.GetValue("SettingsPage_Settings_ResetAppDescription"), "DualSenseX", LocalizationManager.Instance.GetValue("SettingsPage_Settings_ResetAppYesButton"), LocalizationManager.Instance.GetValue("AppNotificationPopUp_Cancel"), (MessageBoxImage)16) == 1)
			{
				try
				{
					if (File.Exists("C:\\Temp\\DualSenseX\\DualSenseX_SaveFile_INI.ini"))
					{
						File.Delete("C:\\Temp\\DualSenseX\\DualSenseX_SaveFile_INI.ini");
						if (App_TaskBarIcon != null)
						{
							((UIElement)App_TaskBarIcon).Visibility = (Visibility)1;
						}
						await Task.Delay(2000);
						Application.Restart();
						Environment.Exit(0);
					}
				}
				catch (Exception)
				{
				}
			}
		});
	}

