	private void SettingsPage_AudioHapticsSyncOptionsDropDown_SelectionChanged(object sender, SelectionChangedEventArgs e)
	{
		if (((Selector)SettingsPage_AudioHapticsSyncOptionsDropDown).SelectedIndex == 0)
		{
			GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_AudioHaptics_SyncOptions = AudioHapticsSyncOptions.SyncAll;
			((UIElement)SettingsPage_AudioHapticsLeftSpeakerVolumeSlider).IsEnabled = false;
			((UIElement)SettingsPage_AudioHapticsRightSpeakerVolumeSlider).IsEnabled = false;
			((UIElement)SettingsPage_AudioHapticsLeftMotorVolumeSlider).IsEnabled = false;
			((UIElement)SettingsPage_AudioHapticsRightMotorVolumeSlider).IsEnabled = false;
		}
		else if (((Selector)SettingsPage_AudioHapticsSyncOptionsDropDown).SelectedIndex == 1)
		{
			GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_AudioHaptics_SyncOptions = AudioHapticsSyncOptions.SyncLeftandRightSpeakers;
			((UIElement)SettingsPage_AudioHapticsLeftSpeakerVolumeSlider).IsEnabled = false;
			((UIElement)SettingsPage_AudioHapticsRightSpeakerVolumeSlider).IsEnabled = false;
			((UIElement)SettingsPage_AudioHapticsLeftMotorVolumeSlider).IsEnabled = true;
			((UIElement)SettingsPage_AudioHapticsRightMotorVolumeSlider).IsEnabled = true;
		}
		else if (((Selector)SettingsPage_AudioHapticsSyncOptionsDropDown).SelectedIndex == 2)
		{
			GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_AudioHaptics_SyncOptions = AudioHapticsSyncOptions.SyncLeftMotorandRightMotor;
			((UIElement)SettingsPage_AudioHapticsLeftSpeakerVolumeSlider).IsEnabled = true;
			((UIElement)SettingsPage_AudioHapticsRightSpeakerVolumeSlider).IsEnabled = true;
			((UIElement)SettingsPage_AudioHapticsLeftMotorVolumeSlider).IsEnabled = false;
			((UIElement)SettingsPage_AudioHapticsRightMotorVolumeSlider).IsEnabled = false;
		}
		else if (((Selector)SettingsPage_AudioHapticsSyncOptionsDropDown).SelectedIndex == 3)
		{
			GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_AudioHaptics_SyncOptions = AudioHapticsSyncOptions.DontSync;
			((UIElement)SettingsPage_AudioHapticsLeftSpeakerVolumeSlider).IsEnabled = true;
			((UIElement)SettingsPage_AudioHapticsRightSpeakerVolumeSlider).IsEnabled = true;
			((UIElement)SettingsPage_AudioHapticsLeftMotorVolumeSlider).IsEnabled = true;
			((UIElement)SettingsPage_AudioHapticsRightMotorVolumeSlider).IsEnabled = true;
		}
		SaveSettingsINI();
	}

	private void SettingsPage_AudioHapticsLeftSpeakerVolumeSlider_ValueChanged(object sender, RoutedPropertyChangedEventArgs<double> e)
	{
		GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_AudioHaptics_LeftSpeakerVolume = (int)((RangeBase)SettingsPage_AudioHapticsLeftSpeakerVolumeSlider).Value;
		if (GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_AudioHaptics_SyncOptions == AudioHapticsSyncOptions.SyncLeftMotorandRightMotor)
		{
			if (PlaybackStream != null && PlaybackStream.PlaybackState == PlaybackState.Playing)
			{
				PlaybackStream.AudioStreamVolume.SetChannelVolume(0, (float)(((RangeBase)SettingsPage_AudioHapticsLeftSpeakerVolumeSlider).Value / 100.0));
			}
		}
		else if (GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_AudioHaptics_SyncOptions == AudioHapticsSyncOptions.DontSync && PlaybackStream != null && PlaybackStream.PlaybackState == PlaybackState.Playing)
		{
			PlaybackStream.AudioStreamVolume.SetChannelVolume(0, (float)(((RangeBase)SettingsPage_AudioHapticsLeftSpeakerVolumeSlider).Value / 100.0));
		}
		SaveSettingsINI();
	}

