	private void SettingsPage_AudioHapticsLeftMotorVolumeSlider_ValueChanged(object sender, RoutedPropertyChangedEventArgs<double> e)
	{
		GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_AudioHaptics_LeftMotorVolume = (int)((RangeBase)SettingsPage_AudioHapticsLeftMotorVolumeSlider).Value;
		if (GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_AudioHaptics_SyncOptions == AudioHapticsSyncOptions.SyncLeftandRightSpeakers)
