				multiplexingWaveProvider5.ConnectInputToOutput(1, 1);
				multiplexingWaveProvider5.ConnectInputToOutput(0, 2);
				multiplexingWaveProvider5.ConnectInputToOutput(1, 3);
				PlaybackStream.Init(multiplexingWaveProvider5);
			}
			WasapiOut playbackStream = PlaybackStream;
