	private void SettingsPage_RefreshoutputDevices_Click(object sender, RoutedEventArgs e)
	{
		try
		{
			if (!((UIElement)SettingsPage_EnableAudioHaptics).IsEnabled)
			{
				return;
			}
			GlobalVar.ListOfOutputDevices.Clear();
			dev = enumer.GetDefaultAudioEndpoint(DataFlow.Render, Role.Multimedia);
			dev.AudioEndpointVolume.OnVolumeNotification += AudioEndpointVolume_OnVolumeNotification;
			MMDeviceEnumerator mMDeviceEnumerator = new MMDeviceEnumerator();
			foreach (MMDevice item in mMDeviceEnumerator.EnumerateAudioEndPoints(DataFlow.Render, DeviceState.Active))
			{
				if (!item.FriendlyName.Contains("Wireless Controller"))
				{
					GlobalVar.ListOfOutputDevices.Add(item.FriendlyName);
				}
			}
			CollectionViewSource.GetDefaultView((object)((ItemsControl)SettingsPage_ListOfOutputDevices).ItemsSource).Refresh();
			((Selector)SettingsPage_ListOfOutputDevices).SelectedItem = mMDeviceEnumerator.GetDefaultAudioEndpoint(DataFlow.Render, Role.Multimedia).FriendlyName;
			SettingsPage_EnableAudioHaptics.IsOn = false;
			SettingsPage_EnableAudioHaptics.IsOn = true;
			GlobalVar.DidDefaultDeviceChange = false;
		}
		catch (Exception)
		{
		}
	}

