	private void SettingsPage_EnableAudioHaptics_Toggled(object sender, RoutedEventArgs e)
	{
		if (SettingsPage_EnableAudioHaptics.IsOn)
		{
			try
			{
				SettingsPage_DisableControllerVibrationSwitch.IsOn = true;
				((ToggleButton)SettingsPage_EnableIncomingVibWhileDisabled).IsChecked = true;
				MMDeviceEnumerator mMDeviceEnumerator = new MMDeviceEnumerator();
				GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_EnableAudioHaptics = true;
				if (GlobalVar.DualSense != null && GlobalVar.DualSense.GetMaxInputReportLength() != 78 && GlobalVar.DualSense.GetMaxInputReportLength() == 64)
				{
					if (GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_Audio_Enable)
					{
						if (GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_Audio_Mode == AudioMode.InternalSpeaker)
						{
							((ContentControl)SettingsPage_AudioHapticsLeftSpeakerVolumeLabel).Content = "-----";
							((ContentControl)SettingsPage_AudioHapticsRightSpeakerVolumeLabel).Content = LocalizationManager.Instance.GetValue("SettingsPage_ControllerSettings_AudioHapticsVolume_Speaker");
						}
						else if (GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_Audio_Mode == AudioMode.Headset)
						{
							((ContentControl)SettingsPage_AudioHapticsLeftSpeakerVolumeLabel).Content = LocalizationManager.Instance.GetValue("SettingsPage_ControllerSettings_AudioHapticsVolume_HeadsetLeft");
							((ContentControl)SettingsPage_AudioHapticsRightSpeakerVolumeLabel).Content = LocalizationManager.Instance.GetValue("SettingsPage_ControllerSettings_AudioHapticsVolume_HeadsetRight");
						}
						else if (GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_Audio_Mode == AudioMode.Both)
						{
							((ContentControl)SettingsPage_AudioHapticsLeftSpeakerVolumeLabel).Content = LocalizationManager.Instance.GetValue("SettingsPage_ControllerSettings_AudioHapticsVolume_Headset");
							((ContentControl)SettingsPage_AudioHapticsRightSpeakerVolumeLabel).Content = LocalizationManager.Instance.GetValue("SettingsPage_ControllerSettings_AudioHapticsVolume_Speaker");
						}
					}
					else
					{
						((ContentControl)SettingsPage_AudioHapticsLeftSpeakerVolumeLabel).Content = LocalizationManager.Instance.GetValue("SettingsPage_ControllerSettings_AudioHapticsVolume_HeadsetLeft");
						((ContentControl)SettingsPage_AudioHapticsRightSpeakerVolumeLabel).Content = LocalizationManager.Instance.GetValue("SettingsPage_ControllerSettings_AudioHapticsVolume_HeadsetRight");
					}
					if (GlobalVar.ListOfOutputDevices.Count > 0)
					{
						if (PlaybackStream != null)
						{
							PlaybackStream.Stop();
							PlaybackStream.Dispose();
						}
						if (CaptureStream != null)
						{
							CaptureStream.Dispose();
						}
						foreach (MMDevice item in mMDeviceEnumerator.EnumerateAudioEndPoints(DataFlow.Render, DeviceState.Active))
						{
							if (item.FriendlyName == (string)((Selector)SettingsPage_ListOfOutputDevices).SelectedItem && GlobalVar.DualSense != null && GlobalVar.DualSense.GetMaxInputReportLength() != 78 && GlobalVar.DualSense.GetMaxInputReportLength() == 64)
							{
								OriginDevice = item;
								foreach (MMDevice item2 in mMDeviceEnumerator.EnumerateAudioEndPoints(DataFlow.Render, DeviceState.Active))
								{
									if (item2.FriendlyName.Contains("Wireless Controller"))
									{
										DestinationDevice = item2;
									}
								}
							}
						}
						switch (OriginDevice.DataFlow)
						{
						case DataFlow.Capture:
							CaptureStream = new WasapiCapture(OriginDevice, useEventSync: true, 10)
							{
								ShareMode = AudioClientShareMode.Shared
							};
							break;
						case DataFlow.Render:
							CaptureStream = new WasapiLoopbackCapture(OriginDevice)
							{
								ShareMode = AudioClientShareMode.Shared
							};
							break;
						case DataFlow.All:
							CaptureStream = new WasapiCapture(OriginDevice, useEventSync: true, 10)
							{
								ShareMode = AudioClientShareMode.Shared
							};
							break;
						}
						Buffer = new WaveInProvider(CaptureStream);
						PlaybackStream = new WasapiOut(DestinationDevice, AudioClientShareMode.Shared, useEventSync: false, 10);
						if (Buffer.WaveFormat.Channels == 1)
						{
							MultiplexingWaveProvider multiplexingWaveProvider = new MultiplexingWaveProvider(new WaveInProvider[1] { Buffer }, 4);
							multiplexingWaveProvider.ConnectInputToOutput(0, 0);
							multiplexingWaveProvider.ConnectInputToOutput(0, 1);
							multiplexingWaveProvider.ConnectInputToOutput(0, 2);
							multiplexingWaveProvider.ConnectInputToOutput(0, 3);
							PlaybackStream.Init(multiplexingWaveProvider);
						}
						else if (Buffer.WaveFormat.Channels == 2)
						{
							MultiplexingWaveProvider multiplexingWaveProvider2 = new MultiplexingWaveProvider(new WaveInProvider[1] { Buffer }, 4);
							multiplexingWaveProvider2.ConnectInputToOutput(0, 0);
							multiplexingWaveProvider2.ConnectInputToOutput(1, 1);
							multiplexingWaveProvider2.ConnectInputToOutput(0, 2);
							multiplexingWaveProvider2.ConnectInputToOutput(1, 3);
							PlaybackStream.Init(multiplexingWaveProvider2);
						}
						else if (Buffer.WaveFormat.Channels == 3)
						{
							MultiplexingWaveProvider multiplexingWaveProvider3 = new MultiplexingWaveProvider(new WaveInProvider[1] { Buffer }, 4);
							multiplexingWaveProvider3.ConnectInputToOutput(0, 0);
							multiplexingWaveProvider3.ConnectInputToOutput(1, 1);
							multiplexingWaveProvider3.ConnectInputToOutput(2, 2);
							multiplexingWaveProvider3.ConnectInputToOutput(2, 3);
							PlaybackStream.Init(multiplexingWaveProvider3);
						}
						else if (Buffer.WaveFormat.Channels == 4)
						{
							MultiplexingWaveProvider multiplexingWaveProvider4 = new MultiplexingWaveProvider(new WaveInProvider[1] { Buffer }, 4);
							multiplexingWaveProvider4.ConnectInputToOutput(0, 0);
							multiplexingWaveProvider4.ConnectInputToOutput(1, 1);
							multiplexingWaveProvider4.ConnectInputToOutput(2, 2);
							multiplexingWaveProvider4.ConnectInputToOutput(3, 3);
							PlaybackStream.Init(multiplexingWaveProvider4);
						}
						WasapiOut playbackStream = PlaybackStream;
						if (playbackStream == null || playbackStream.PlaybackState != PlaybackState.Playing)
						{
							CaptureStream?.StartRecording();
							PlaybackStream?.Play();
						}
						dev = enumer.GetDefaultAudioEndpoint(DataFlow.Render, Role.Multimedia);
						dev.AudioEndpointVolume.OnVolumeNotification += AudioEndpointVolume_OnVolumeNotification;
					}
					else
					{
						foreach (MMDevice item3 in mMDeviceEnumerator.EnumerateAudioEndPoints(DataFlow.Render, DeviceState.Active))
						{
							if (!item3.FriendlyName.Contains("Wireless Controller"))
							{
								GlobalVar.ListOfOutputDevices.Add(item3.FriendlyName);
							}
						}
						((ItemsControl)SettingsPage_ListOfOutputDevices).ItemsSource = GlobalVar.ListOfOutputDevices;
						((Selector)SettingsPage_ListOfOutputDevices).SelectedItem = mMDeviceEnumerator.GetDefaultAudioEndpoint(DataFlow.Render, Role.Multimedia).FriendlyName;
					}
				}
				SaveSettingsINI();
				return;
			}
			catch (Exception)
			{
				return;
			}
		}
		try
		{
			if (GlobalVar.Savefile.SaveFile_DisableControllerVibration)
			{
				SettingsPage_DisableControllerVibrationSwitch.IsOn = true;
				if (GlobalVar.Savefile.SaveFile_EnableIncomingVibrationsWhileDisabled)
				{
					((ToggleButton)SettingsPage_EnableIncomingVibWhileDisabled).IsChecked = true;
				}
				else
				{
					((ToggleButton)SettingsPage_EnableIncomingVibWhileDisabled).IsChecked = false;
				}
			}
			else
			{
				SettingsPage_DisableControllerVibrationSwitch.IsOn = false;
				((UIElement)SettingsPage_EnableIncomingVibWhileDisabled).IsEnabled = false;
			}
			GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_EnableAudioHaptics = false;
			if (PlaybackStream != null)
			{
				PlaybackStream.Stop();
				PlaybackStream.Dispose();
			}
			if (CaptureStream != null)
			{
				CaptureStream.Dispose();
			}
			SaveSettingsINI();
		}
		catch (Exception)
		{
		}
	}

	private void AudioEndpointVolume_OnVolumeNotification(AudioVolumeNotificationData data)
	{
		if (PlaybackStream != null && PlaybackStream.PlaybackState == PlaybackState.Playing)
		{
			if (GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_AudioHaptics_SyncOptions == AudioHapticsSyncOptions.SyncAll)
			{
				((DispatcherObject)this).Dispatcher.Invoke((Action)delegate
				{
					((RangeBase)SettingsPage_AudioHapticsLeftSpeakerVolumeSlider).Value = data.MasterVolume * 100f;
					((RangeBase)SettingsPage_AudioHapticsRightSpeakerVolumeSlider).Value = data.MasterVolume * 100f;
					((RangeBase)SettingsPage_AudioHapticsLeftMotorVolumeSlider).Value = data.MasterVolume * 100f;
					((RangeBase)SettingsPage_AudioHapticsRightMotorVolumeSlider).Value = data.MasterVolume * 100f;
				});
				PlaybackStream.AudioStreamVolume.SetChannelVolume(0, data.MasterVolume);
				PlaybackStream.AudioStreamVolume.SetChannelVolume(1, data.MasterVolume);
				PlaybackStream.AudioStreamVolume.SetChannelVolume(2, data.MasterVolume);
				PlaybackStream.AudioStreamVolume.SetChannelVolume(3, data.MasterVolume);
			}
			else if (GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_AudioHaptics_SyncOptions == AudioHapticsSyncOptions.SyncLeftandRightSpeakers)
			{
				PlaybackStream.AudioStreamVolume.SetChannelVolume(0, data.MasterVolume);
				PlaybackStream.AudioStreamVolume.SetChannelVolume(1, data.MasterVolume);
				((DispatcherObject)this).Dispatcher.Invoke((Action)delegate
				{
					((RangeBase)SettingsPage_AudioHapticsLeftSpeakerVolumeSlider).Value = data.MasterVolume * 100f;
					((RangeBase)SettingsPage_AudioHapticsRightSpeakerVolumeSlider).Value = data.MasterVolume * 100f;
				});
			}
			else if (GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_AudioHaptics_SyncOptions == AudioHapticsSyncOptions.SyncLeftMotorandRightMotor)
			{
				((DispatcherObject)this).Dispatcher.Invoke((Action)delegate
				{
					((RangeBase)SettingsPage_AudioHapticsLeftMotorVolumeSlider).Value = data.MasterVolume * 100f;
					((RangeBase)SettingsPage_AudioHapticsRightMotorVolumeSlider).Value = data.MasterVolume * 100f;
				});
				PlaybackStream.AudioStreamVolume.SetChannelVolume(2, data.MasterVolume);
				PlaybackStream.AudioStreamVolume.SetChannelVolume(3, data.MasterVolume);
			}
		}
		if (GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_Audio_Mode == AudioMode.InternalSpeaker)
		{
			((DispatcherObject)this).Dispatcher.Invoke((Action)delegate
			{
				((RangeBase)SettingsPage_Audio_SpeakerVolume).Value = data.MasterVolume * 100f;
			});
		}
		else if (GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_Audio_Mode == AudioMode.Headset)
		{
			((DispatcherObject)this).Dispatcher.Invoke((Action)delegate
			{
				((RangeBase)SettingsPage_Audio_HeadsetVolume).Value = data.MasterVolume * 100f;
			});
		}
		else if (GlobalVar.Savefile.SaveFile_ControllerAudio.SaveFile_Audio_Mode == AudioMode.Both)
		{
			((DispatcherObject)this).Dispatcher.Invoke((Action)delegate
			{
				((RangeBase)SettingsPage_Audio_SpeakerVolume).Value = data.MasterVolume * 100f;
				((RangeBase)SettingsPage_Audio_HeadsetVolume).Value = data.MasterVolume * 100f;
			});
		}
	}

