	private void SettingsPage_UDPListenToggle_Toggled(object sender, RoutedEventArgs e)
	{
		if (SettingsPage_UDPListenToggle.IsOn)
		{
			GlobalVar.Savefile.SaveFile_UDPListen = true;
			if (GlobalVar.IsControllerConnectedStatus)
			{
				isUsingUDPServer = true;
				UpdateTriggerModesFromUDPServer(GlobalVar.Savefile.SaveFile_UDPPortNumber);
			}
			SaveSettingsINI();
			return;
		}
		GlobalVar.Savefile.SaveFile_UDPListen = false;
		if (UDPTask != null && UDPTask.Status == TaskStatus.Running)
		{
			UDPServer.Close();
			isUsingUDPServer = false;
			UDPTask = null;
		}
		isUsingUDPServer = false;
		SaveSettingsINI();
	}

	private async void SettingsPage_UDPListenNumberbox_ValueChanged(NumberBox sender, NumberBoxValueChangedEventArgs args)
	{
		GlobalVar.Savefile.SaveFile_UDPPortNumber = (int)SettingsPage_UDPListenNumberbox.Value;
		if (UDPTask != null && UDPTask.Status == TaskStatus.Running)
		{
			isUsingUDPServer = false;
			UDPTask = null;
			UDPServer.Close();
		}
		await Task.Delay(500);
		if (GlobalVar.IsControllerConnectedStatus)
		{
			isUsingUDPServer = true;
			UpdateTriggerModesFromUDPServer(Convert.ToInt32(GlobalVar.Savefile.SaveFile_UDPPortNumber));
		}
		File.WriteAllText("C:\\Temp\\DualSenseX\\DualSenseX_PortNumber.txt", $"{GlobalVar.Savefile.SaveFile_UDPPortNumber}");
		SaveSettingsINI();
	}

