	public async void PlayLightShow(string ColorMode)
	{
		connectedController.SetMicLedStatus(MicLED.PULSE);
		connectedController.ControllerVibration(leftMotor: false, rightMotor: false, bothMotors: true, 10);
		connectedController.SetPlayerLedStatus(PlayerLED.AllOn, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED1, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED2, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED3, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED4, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED5);
		GlobalVar.IsAppLaunched = false;
		Color randomColour = GetRandomColour();
		connectedController.SetLedColorRGB(randomColour.R, randomColour.G, randomColour.B);
		await Task.Delay(500);
		connectedController.ControllerVibration(leftMotor: false, rightMotor: false, bothMotors: true, 43);
		connectedController.SetPlayerLedStatus(PlayerLED.ONE, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED1, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED2, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED3, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED4, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED5);
		Color randomColour2 = GetRandomColour();
		connectedController.SetLedColorRGB(randomColour2.R, randomColour2.G, randomColour2.B);
		await Task.Delay(500);
		connectedController.ControllerVibration(leftMotor: false, rightMotor: false, bothMotors: true, 85);
		connectedController.SetPlayerLedStatus(PlayerLED.TWO, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED1, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED2, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED3, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED4, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED5);
		Color randomColour3 = GetRandomColour();
		connectedController.SetLedColorRGB(randomColour3.R, randomColour3.G, randomColour3.B);
		await Task.Delay(500);
		connectedController.ControllerVibration(leftMotor: false, rightMotor: false, bothMotors: true, 127);
		connectedController.SetPlayerLedStatus(PlayerLED.THREE, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED1, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED2, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED3, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED4, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED5);
		Color randomColour4 = GetRandomColour();
		connectedController.SetLedColorRGB(randomColour4.R, randomColour4.G, randomColour4.B);
		await Task.Delay(500);
		connectedController.ControllerVibration(leftMotor: false, rightMotor: false, bothMotors: true, 169);
		connectedController.SetPlayerLedStatus(PlayerLED.FOUR, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED1, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED2, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED3, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED4, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED5);
		Color randomColour5 = GetRandomColour();
		connectedController.SetLedColorRGB(randomColour5.R, randomColour5.G, randomColour5.B);
		await Task.Delay(500);
		connectedController.ControllerVibration(leftMotor: false, rightMotor: false, bothMotors: true, 211);
		connectedController.SetPlayerLedStatus(PlayerLED.FIVE, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED1, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED2, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED3, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED4, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED5);
		Color randomColour6 = GetRandomColour();
		connectedController.SetLedColorRGB(randomColour6.R, randomColour6.G, randomColour6.B);
		await Task.Delay(500);
		connectedController.ControllerVibration(leftMotor: false, rightMotor: false, bothMotors: true, byte.MaxValue);
		connectedController.SetPlayerLedStatus(PlayerLED.AllOn, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED1, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED2, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED3, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED4, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED5);
		Color randomColour7 = GetRandomColour();
		connectedController.SetLedColorRGB(randomColour7.R, randomColour7.G, randomColour7.B);
		await Task.Delay(1000);
		if (GlobalVar.IsControllerConnectedStatus)
		{
			connectedController.ControllerVibration(leftMotor: false, rightMotor: false, bothMotors: true, 0);
			connectedController.SetPlayerLedStatus(PlayerLED.AllOff, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED1, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED2, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED3, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED4, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED5);
			connectedController.SetMicLedStatus(MicLED.OFF);
			if (ColorMode == "Static Color")
			{
				GlobalVar.Savefile.SaveFile_ControllerLEDColorMode = TouchpadColorMode.StaticColor;
				Color saveFile_TouchpadLEDColor = GlobalVar.Savefile.SaveFile_TouchpadLEDColor;
				connectedController.SetLedColorRGB(((Color)(ref saveFile_TouchpadLEDColor)).R, ((Color)(ref saveFile_TouchpadLEDColor)).G, ((Color)(ref saveFile_TouchpadLEDColor)).B);
			}
			else if (ColorMode == "Rainbow")
			{
				GlobalVar.Savefile.SaveFile_ControllerLEDColorMode = TouchpadColorMode.Rainbow;
				RainbowTimer.Stop();
				_r = byte.MaxValue;
				_g = 0;
				_b = 0;
				RainbowTimer = new DispatcherTimer();
				switch (GlobalVar.Savefile.SaveFile_RainbowSpeedMode)
				{
				case RainbowSpeedMode.Slow:
					RainbowTimer.Interval = TimeSpan.FromMilliseconds(0.001);
					break;
				case RainbowSpeedMode.Medium:
					RainbowTimer.Interval = TimeSpan.Zero;
					break;
				case RainbowSpeedMode.Fast:
					RainbowTimer.Interval = TimeSpan.Zero;
					break;
				case RainbowSpeedMode.Hyper:
					RainbowTimer.Interval = TimeSpan.Zero;
					break;
				default:
					RainbowTimer.Interval = TimeSpan.Zero;
					break;
				}
				RainbowTimer.Tick += RainbowTimerFunc;
				RainbowTimer.Start();
			}
			connectedController.TouchpadLEDBrightness(GlobalVar.Savefile.SaveFile_TouchpadLEDBrightness);
			connectedController.SetPlayerLedStatus(GlobalVar.Savefile.SaveFile_ControllerPLayerLED, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED1, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED2, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED3, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED4, GlobalVar.Savefile.SaveFile_PlayerLEDCustom.PlayerLED5);
			connectedController.SetMicLedStatus(GlobalVar.Savefile.SaveFile_MicLED);
			connectedController.SetPlayerLedBrightness(GlobalVar.Savefile.SaveFile_PlayerLEDBrightness);
		}
		((UIElement)SettingsPage_PreviewLightshowBtn).IsEnabled = true;
	}

