		{
			GlobalVar.Savefile.SaveFile_StartAppOnWindowsStartup = true;
			SaveSettingsINI();
			((UIElement)SettingsPage_LaunchAppOnStartupMinimizedCheckbox).IsEnabled = true;
			((ToggleButton)SettingsPage_LaunchAppOnStartupMinimizedCheckbox).IsChecked = false;
			try
			{
				RegistryKey obj = Registry.CurrentUser.OpenSubKey("SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Run", true);
				Path.GetDirectoryName(Assembly.GetExecutingAssembly().Location + "\\DualSenseX.exe");
				obj.SetValue("DualSenseX", (object)(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData) + "\\DualSenseX\\DualSenseX.exe"));
				return;
			}
			catch (Exception)
			{
				return;
			}
		}
		GlobalVar.Savefile.SaveFile_StartAppOnWindowsStartup = false;
		SaveSettingsINI();
		((UIElement)SettingsPage_LaunchAppOnStartupMinimizedCheckbox).IsEnabled = false;
		((ToggleButton)SettingsPage_LaunchAppOnStartupMinimizedCheckbox).IsChecked = false;
		try
		{
			Registry.CurrentUser.OpenSubKey("SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Run", true).DeleteValue("DualSenseX", false);
		}
		catch (Exception)
		{
		}
	}

