	private void KillSteamInBackground()
	{
		if (File.Exists("C:\\Temp\\DualSenseX\\KillSteamCommand.bat"))
		{
			Process process = new Process();
			process.StartInfo = new ProcessStartInfo
			{
				UseShellExecute = true,
				WindowStyle = ProcessWindowStyle.Hidden,
				FileName = "C:\\Temp\\DualSenseX\\KillSteamCommand.bat"
			};
			process.Start();
			return;
		}
		string contents = "taskkill.exe /F /IM steam.exe" + Environment.NewLine;
		string path = "C:\\Temp\\DualSenseX\\";
		File.WriteAllText(Path.Combine(path, "KillSteamCommand.bat"), contents);
		string[] contents2 = new string[1] { "exit" };
		File.AppendAllLines(Path.Combine(path, "KillSteamCommand.bat"), contents2);
		Process process2 = new Process();
		process2.StartInfo = new ProcessStartInfo
		{
			UseShellExecute = true,
			WindowStyle = ProcessWindowStyle.Hidden,
			FileName = "C:\\Temp\\DualSenseX\\KillSteamCommand.bat"
		};
		process2.Start();
	}

