	private void GenerateRandomTriggerModesBtn_Click(object sender, RoutedEventArgs e)
	{
		byte[] array = new byte[9] { 2, 1, 6, 33, 34, 35, 37, 38, 39 };
		Random random = new Random();
		int num = random.Next(array.Length);
		int num2 = random.Next(array.Length);
		int num3 = random.Next(array.Length);
		int num4 = random.Next(array.Length);
		int num5 = random.Next(array.Length);
		int num6 = random.Next(array.Length);
		int num7 = random.Next(array.Length);
		int num8 = random.Next(array.Length);
		byte randByte = array[num];
		byte randByte2 = array[num2];
		byte randByte3 = array[num3];
		byte randByte4 = array[num4];
		byte randByte5 = array[num5];
		byte randByte6 = array[num6];
		byte randByte7 = array[num7];
		byte randByte8 = array[num8];
		GlobalVar.randByte1 = randByte;
		GlobalVar.randByte2 = randByte2;
		GlobalVar.randByte3 = randByte3;
		GlobalVar.randByte4 = randByte4;
		GlobalVar.randByte5 = randByte5;
		GlobalVar.randByte6 = randByte6;
		GlobalVar.randByte7 = randByte7;
		GlobalVar.randByte8 = randByte8;
	}

